26	template<typename T>
27	void GptJ<T>::initialize()
28	{
29	    gpt_context_decoder_ = new GptJContextDecoder<T>(0,
30	                                                     0,
31	                                                     head_num_,
32	                                                     size_per_head_,
33	                                                     inter_size_,
34	                                                     num_layer_,
35	                                                     rotary_embedding_dim_,
36	                                                     neox_rotary_style_,
37	                                                     layernorm_eps_,
38	                                                     tensor_para_,
39	                                                     pipeline_para_,
40	                                                     stream_,
41	                                                     cublas_wrapper_,
42	                                                     allocator_,
43	                                                     is_free_buffer_after_forward_,
44	                                                     is_context_qk_buf_float_,
45	                                                     attention_type_,
46	                                                     custom_all_reduce_comm_,
47	                                                     enable_custom_all_reduce_);
48	
49	    gpt_decoder_ = new GptJDecoder<T>(0,
50	                                      head_num_,
51	                                      size_per_head_,
52	                                      inter_size_,
53	                                      num_layer_,
54	                                      rotary_embedding_dim_,
55	                                      neox_rotary_style_,
56	                                      layernorm_eps_,
57	                                      tensor_para_,
58	                                      pipeline_para_,
59	                                      stream_,
60	                                      cublas_wrapper_,
61	                                      allocator_,
62	                                      is_free_buffer_after_forward_,
63	                                      custom_all_reduce_comm_,
64	                                      enable_custom_all_reduce_);
65	
66	    dynamic_decode_layer_ = new DynamicDecodeLayer<float>(vocab_size_,
67	                                                          vocab_size_padded_,
68	                                                          0,  // end_id, deprecated
69	                                                          stream_,
70	                                                          cublas_wrapper_,
71	                                                          allocator_,
72	                                                          is_free_buffer_after_forward_,
73	                                                          cuda_device_prop_);
74	}
