82	template<typename T>
83	void GptJ<T>::allocateBuffer(
84	    size_t batch_size, size_t beam_width, size_t max_seq_len, size_t max_cache_seq_len, size_t max_input_len)
85	{
86	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
87	    const size_t batchxbeam      = batch_size * beam_width;
88	    const size_t self_cache_size = (num_layer_ / pipeline_para_.world_size_) * batchxbeam * max_cache_seq_len
89	                                   * hidden_units_ / tensor_para_.world_size_;
90	
91	    if (vocab_size_ != vocab_size_padded_) {
92	        padded_embedding_kernel_ =
93	            (T*)(allocator_->reMalloc(padded_embedding_kernel_, sizeof(T) * hidden_units_ * vocab_size_padded_, true));
94	        padded_embedding_kernel_ptr_ = padded_embedding_kernel_;
95	
96	        padded_embedding_bias_ =
97	            (T*)(allocator_->reMalloc(padded_embedding_bias_, sizeof(T) * vocab_size_padded_, true));
98	        padded_embedding_bias_ptr_ = padded_embedding_bias_;
99	    }
100	
101	    // TODO : memory allocation optimization --> [max_input_len, max_input_len + max_prefix_prompt_len]
102	    input_attention_mask_ = (T*)(allocator_->reMalloc(
103	        input_attention_mask_, sizeof(T) * batchxbeam * max_seq_len * max_cache_seq_len, false));
104	    decoder_input_buf_ = (T*)(allocator_->reMalloc(decoder_input_buf_, sizeof(T) * batchxbeam * hidden_units_, false));
105	    decoder_output_buf_ =
106	        (T*)(allocator_->reMalloc(decoder_output_buf_, sizeof(T) * batchxbeam * hidden_units_, false));
107	    normed_decoder_output_buf_ =
108	        (T*)(allocator_->reMalloc(normed_decoder_output_buf_, sizeof(T) * batchxbeam * hidden_units_, false));
109	    logits_buf_ = (float*)(allocator_->reMalloc(logits_buf_, sizeof(float) * batchxbeam * vocab_size_padded_, false));
110	    nccl_logits_buf_ =
111	        (float*)(allocator_->reMalloc(nccl_logits_buf_, sizeof(float) * batchxbeam * vocab_size_padded_, false));
112	    cum_log_probs_    = (float*)(allocator_->reMalloc(cum_log_probs_, sizeof(float) * batchxbeam, false));
113	    finished_buf_     = (bool*)(allocator_->reMalloc(finished_buf_, sizeof(bool) * batchxbeam, false));
114	    sequence_lengths_ = (int*)(allocator_->reMalloc(sequence_lengths_, sizeof(int) * batchxbeam, false));
115	    masked_tokens_ = (bool*)(allocator_->reMalloc(masked_tokens_, sizeof(bool) * batchxbeam * max_cache_seq_len, true));
116	
117	    h_finished_buf_ = new bool[batchxbeam];
118	
119	    key_cache_   = (T*)(allocator_->reMalloc(key_cache_, sizeof(T) * self_cache_size * 2, true));
120	    value_cache_ = key_cache_ + self_cache_size;
121	    if (beam_width > 1) {
122	        cache_indirections_[0] = (int*)(allocator_->reMalloc(
123	            cache_indirections_[0], sizeof(int) * batchxbeam * max_cache_seq_len * 2, true));
124	        cache_indirections_[1] = cache_indirections_[0] + batchxbeam * max_cache_seq_len;
125	    }
126	    tiled_total_padding_count_ =
127	        (int*)allocator_->reMalloc(tiled_total_padding_count_, batchxbeam * sizeof(int), false);
128	
129	    // prompt_learning weight batch ptrs
130	    prompt_learning_weight_batch_ =
131	        (const T**)(allocator_->reMalloc(prompt_learning_weight_batch_, sizeof(T*) * batchxbeam, false));
132	    tiled_prompt_lengths_buf_ =
133	        (int*)(allocator_->reMalloc(tiled_prompt_lengths_buf_, sizeof(int) * batchxbeam, false));
134	
135	    tiled_input_ids_buf_ =
136	        (int*)(allocator_->reMalloc(tiled_input_ids_buf_, sizeof(int) * batchxbeam * max_input_len, true));
137	    tiled_input_lengths_buf_ = (int*)(allocator_->reMalloc(tiled_input_lengths_buf_, sizeof(int) * batchxbeam, true));
138	
139	    transposed_output_ids_buf_ =
140	        (int*)(allocator_->reMalloc(transposed_output_ids_buf_, sizeof(int) * batchxbeam * max_seq_len, true));
141	    output_ids_buf_ = (int*)(allocator_->reMalloc(output_ids_buf_, sizeof(int) * batchxbeam * max_seq_len, true));
142	    parent_ids_buf_ = (int*)(allocator_->reMalloc(parent_ids_buf_, sizeof(int) * batchxbeam * max_seq_len, true));
143	
144	    start_ids_buf_ = (int*)(allocator_->reMalloc(start_ids_buf_, sizeof(int) * batch_size, false));
145	    end_ids_buf_   = (int*)(allocator_->reMalloc(end_ids_buf_, sizeof(int) * batch_size, false));
146	    seq_limit_len_ = (uint32_t*)(allocator_->reMalloc(seq_limit_len_, sizeof(uint32_t) * batch_size, false));
147	
148	    context_decoder_input_buf_  = (T*)(allocator_->reMalloc(
149	        context_decoder_input_buf_, sizeof(T) * batchxbeam * max_input_len * hidden_units_, false));
150	    context_decoder_output_buf_ = (T*)(allocator_->reMalloc(
151	        context_decoder_output_buf_, sizeof(T) * batchxbeam * max_input_len * hidden_units_, false));
152	    output_log_probs_buf_ =
153	        (float*)(allocator_->reMalloc(output_log_probs_buf_, sizeof(float) * batchxbeam * max_seq_len, false));
154	    generation_should_stop_ = (bool*)(allocator_->reMalloc(generation_should_stop_, sizeof(bool), true, true));
155	
156	    is_allocate_buffer_ = true;
157	}
158	
159	template<typename T>
160	void GptJ<T>::freeBuffer()
161	{
162	    if (is_allocate_buffer_) {
163	        if (vocab_size_ != vocab_size_padded_) {
164	            padded_embedding_kernel_ptr_ = nullptr;
165	            padded_embedding_bias_ptr_   = nullptr;
166	            allocator_->free((void**)(&padded_embedding_kernel_));
167	            allocator_->free((void**)(&padded_embedding_bias_));
168	        }
169	
170	        allocator_->free((void**)(&input_attention_mask_));
171	        allocator_->free((void**)(&decoder_input_buf_));
172	        allocator_->free((void**)(&decoder_output_buf_));
173	        allocator_->free((void**)(&normed_decoder_output_buf_));
174	        allocator_->free((void**)(&logits_buf_));
175	        allocator_->free((void**)(&nccl_logits_buf_));
176	        allocator_->free((void**)(&cum_log_probs_));
177	        allocator_->free((void**)(&sequence_lengths_));
178	        allocator_->free((void**)(&finished_buf_));
179	        delete[] h_finished_buf_;
180	
181	        allocator_->free((void**)(&key_cache_));
182	        if (cache_indirections_[0] != nullptr) {
183	            allocator_->free((void**)(&cache_indirections_)[0]);
184	        }
185	
186	        allocator_->free((void**)(&prompt_learning_weight_batch_));
187	        allocator_->free((void**)(&tiled_prompt_lengths_buf_));
188	        allocator_->free((void**)(&tiled_total_padding_count_));
189	
190	        allocator_->free((void**)(&tiled_input_ids_buf_));
191	        allocator_->free((void**)(&tiled_input_lengths_buf_));
192	
193	        allocator_->free((void**)(&transposed_output_ids_buf_));
194	        allocator_->free((void**)(&output_ids_buf_));
195	        allocator_->free((void**)(&parent_ids_buf_));
196	        allocator_->free((void**)(&masked_tokens_));
197	
198	        allocator_->free((void**)(&start_ids_buf_));
199	        allocator_->free((void**)(&end_ids_buf_));
200	        allocator_->free((void**)(&seq_limit_len_));
201	
202	        allocator_->free((void**)(&context_decoder_input_buf_));
203	        allocator_->free((void**)(&context_decoder_output_buf_));
204	        allocator_->free((void**)(&output_log_probs_buf_));
205	
206	        allocator_->free((void**)(&generation_should_stop_), true);
207	
208	        is_allocate_buffer_ = false;
209	    }
210	}
