212	template<typename T>
213	GptJ<T>::GptJ(size_t                              max_batch_size,
214	              size_t                              max_seq_len,
215	              size_t                              max_input_len,
216	              size_t                              beam_width,
217	              size_t                              head_num,
218	              size_t                              size_per_head,
219	              size_t                              inter_size,
220	              size_t                              num_layer,
221	              size_t                              vocab_size,
222	              size_t                              rotary_embedding_dim,
223	              int                                 start_id,
224	              int                                 end_id,
225	              int                                 prompt_learning_start_id,  // only needed by p/prompt-tuning
226	              PromptLearningType                  prompt_learning_type,
227	              float                               beam_search_diversity_rate,
228	              size_t                              top_k,
229	              float                               top_p,
230	              unsigned long long                  random_seed,
231	              float                               temperature,
232	              float                               len_penalty,
233	              float                               repetition_penalty,
234	              cudaStream_t                        stream,
235	              cublasMMWrapper*                    cublas_wrapper,
236	              IAllocator*                         allocator,
237	              bool                                is_free_buffer_after_forward,
238	              cudaDeviceProp*                     cuda_device_prop,
239	              AttentionType                       attention_type,
240	              std::shared_ptr<AbstractCustomComm> custom_all_reduce_comm,
241	              int                                 enable_custom_all_reduce):
242	    BaseLayer(stream, cublas_wrapper, allocator, is_free_buffer_after_forward, cuda_device_prop),
243	    head_num_(head_num),
244	    size_per_head_(size_per_head),
245	    inter_size_(inter_size),
246	    num_layer_(num_layer),
247	    vocab_size_(vocab_size),
248	    rotary_embedding_dim_(rotary_embedding_dim),
249	    start_id_(start_id),
250	    end_id_(end_id),
251	    prompt_learning_start_id_(prompt_learning_start_id),
252	    prompt_learning_type_(prompt_learning_type),
253	    hidden_units_(head_num * size_per_head),
254	    local_head_num_(head_num / 1),
255	    attention_type_(attention_type)
256	{
257	    tensor_para_.world_size_   = 1;
258	    tensor_para_.rank_         = 0;
259	    pipeline_para_.world_size_ = 1;
260	    pipeline_para_.rank_       = 0;
261	
262	    int local_vacab_size = ceil(vocab_size_ / 1.f / tensor_para_.world_size_);
263	    if (std::is_same<half, T>::value) {
264	        local_vacab_size = ceil(local_vacab_size / 8.f) * 8;
265	    }
266	    vocab_size_padded_ = (size_t)local_vacab_size * tensor_para_.world_size_;
267	    initialize();
268	}
