377	template<typename T>
378	void GptJ<T>::forward(std::vector<Tensor>*       output_tensors,
379	                      const std::vector<Tensor>* input_tensors,
380	                      const GptJWeight<T>*       gpt_weights)
381	{
382	    FT_CHECK(false);
383	}
384	
385	template<typename T>
386	void GptJ<T>::forward(std::unordered_map<std::string, Tensor>*       output_tensors,
387	                      const std::unordered_map<std::string, Tensor>* input_tensors,
388	                      const GptJWeight<T>*                           gpt_weights)
389	{
390	    // input_tensors:
391	    //      input_ids [batch_size, max_input_length]
392	    //      input_lengths [batch_size]
393	    //      prompt_learning_task_name_ids [batch_size] on cpu, optional
394	    //      output_seq_len [batch_size] on cpu
395	    //      start_id [batch_size] on cpu, optional
396	    //      end_id [batch_size] on cpu, optional
397	    //      stop_words_list [batch_size, 2, stop_words_length], optional
398	    //      bad_words_list [2, bad_words_length] or [batch_size, 2, bad_words_length], optional
399	    //      runtime_top_k [1] or [batch_size] on cpu, optional, uint.
400	    //      runtime_top_p [1] or [batch_size] on cpu, optional, float.
401	    //      beam_search_diversity_rate [1] or [batch_size] on cpu, optional, float.
402	    //      temperature [1] or [batch_size] on cpu, optional, float.
403	    //      len_penalty [1] or [batch_size] on cpu, optional, float.
404	    //      repetition_penalty [1] or [batch_size] on cpu, optional, float.
405	    //      min_length [1] or [batch_size] on cpu, optional, int
406	    //      random_seed [1] or [batch_size] on cpu, optional, unsigned long long int.
407	    //      request_prompt_lengths [batch_size], optional
408	    //      request_prompt_embedding [batch_size, max_prompt_length, hidden_units], float, optional
409	    //      requst_prompt_type [batch_size], int, optional
410	    //      memory_len [1] on cpu, uint32, optional
411	    //      top_p_decay [batch_size] on gpu, float, optional
412	    //      top_p_min [batch_size] on gpu, float, optional
413	    //      top_p_reset_ids [batch_size] on gpu, uint32, optional
414	    //      top_p_decay [batch_size] on gpu, float, optional
415	    //      top_p_min [batch_size] on gpu, float, optional
416	    //      top_p_reset_ids [batch_size] on gpu, uint32, optional
417	
418	    // output_tensors:
419	    //      output_ids [batch_size, beam_width, max_output_seq_len]
420	    //      sequence_length [batch_size, beam_width]
421	    //      output_log_probs [batch_size, beam_width, request_output_seq_len], must be float*.
422	    //          optional. It leads to additional computing cost. If we don't need this result, don't put it.
423	    //      cum_log_probs [batch_size, beam], optional, must be float*.
424	    //          optional. It leads to additional computing cost. If we don't need this result, don't put it.
425	
426	    // Step is from max_input_length ~ max_output_seq_len,
427	    // When step = k,  we put output ids and caches at step k, and the sequence_length would be k - 1 before
428	    // complete this step.
429	    // When there is no input_ids, put the start token at step 0 of output_ids_buf_. After forward, only copy
430	    // the step 1 ~ max_output_seq_len of output_ids_buf_ to output_tensors->at(0).data
431	
432	    FT_CHECK_WITH_INFO(input_tensors->size() >= 3, "input_tensors->size() >= 3");
433	    FT_CHECK_WITH_INFO(output_tensors->size() >= 2, "output_tensors->size() >= 2");
434	    FT_CHECK(input_tensors->at("input_ids").shape.size() == 2);
435	    FT_CHECK(input_tensors->at("input_lengths").shape.size() == 1);
436	    FT_CHECK(input_tensors->find("output_seq_len") != input_tensors->end()
437	             && input_tensors->at("output_seq_len").shape.size() == 1);
438	    FT_CHECK(output_tensors->at("output_ids").shape.size() == 3);
439	    FT_CHECK(output_tensors->at("sequence_length").shape.size() == 2);
440	    FT_CHECK_WITH_INFO(input_tensors->at("input_ids").shape[0] == output_tensors->at("output_ids").shape[0],
441	                       "input_tensors->at(\"input_ids\").shape[0] == output_tensors->at(\"output_ids\").shape[0]");
442	
443	    const size_t batch_size = output_tensors->at("output_ids").shape[0];
444	    const size_t beam_width = output_tensors->at("output_ids").shape[1];
445	
446	    PromptLearningType request_prompt_type = PromptLearningType::no_prompt;
447	    int                valid_prompt_inputs = input_tensors->count("request_prompt_type")
448	                              + input_tensors->count("request_prompt_lengths")
449	                              + input_tensors->count("request_prompt_embedding");
450	
451	    if (valid_prompt_inputs == 3) {
452	        request_prompt_type = static_cast<PromptLearningType>(input_tensors->at("request_prompt_type").getVal<int>());
453	        FT_LOG_INFO("Apply prompt embedding from input, will ignore task name ids");
454	    }
455	    else if (valid_prompt_inputs > 0) {
456	        FT_LOG_WARNING(
457	            "Prompts not applied: request_prompt_embedding, request_prompt_lengths, request_prompt_type are all needed!");
458	    }
459	    if (request_prompt_type == PromptLearningType::prefix_prompt) {
460	        FT_LOG_WARNING("Request prompt doesn't support prefix prompt currently!");
461	    }
462	
463	    // Prefix Prompt Inputs
