942	                                          stream_);
943	                }
944	
945	                invokeGenericActivation<IdentityActivation, float, T>(logits_buf_ + vocab_size_units_offset,
946	                                                                      padded_embedding_bias_ptr_,
947	                                                                      nullptr,
948	                                                                      nullptr,
949	                                                                      nullptr,
950	                                                                      nullptr,
951	                                                                      local_batch_size * beam_width,
952	                                                                      vocab_size_padded_,
953	                                                                      0,
954	                                                                      nullptr,
955	                                                                      nullptr,
956	                                                                      stream_);
957	
958	                int                                     tmp_local_batch_size       = local_batch_size;
959	                bool                                    is_initialize_random_table = step == max_input_length;
960	                std::unordered_map<std::string, Tensor> dynamic_decode_input_tensors{
961	                    {"logits",
962	                     Tensor{MEMORY_GPU, TYPE_FP32, {batch_size, beam_width, vocab_size_padded_}, logits_buf_}},
963	                    // {"embedding_bias", Tensor{MEMORY_GPU, data_type, {vocab_size_padded_}, nullptr}},
964	                    {"step", Tensor{MEMORY_CPU, TYPE_INT32, {1}, &step}},
965	                    {"max_input_length", Tensor{MEMORY_CPU, TYPE_INT32, {1}, &max_input_length}},
966	                    {"input_lengths",
967	                     Tensor{MEMORY_GPU, TYPE_INT32, {batch_size, beam_width}, tiled_input_lengths_buf_}},
968	                    {"sequence_limit_length", Tensor{MEMORY_GPU, TYPE_UINT32, {batch_size}, seq_limit_len_}},
969	                    {"ite", Tensor{MEMORY_CPU, TYPE_UINT32, {1}, &ite}},
970	                    {"src_cache_indirection",
971	                     Tensor{MEMORY_GPU,
972	                            TYPE_INT32,
973	                            {local_batch_size, beam_width, max_output_seq_len},
974	                            cache_indirections_[src_indir_idx] + id_offset * max_output_seq_len}},
975	                    {"local_batch_size", Tensor{MEMORY_CPU, TYPE_INT32, {1}, &tmp_local_batch_size}},
976	                    {"end_id", Tensor{MEMORY_GPU, TYPE_INT32, {batch_size}, end_ids_buf_}},
977	                    {"is_initialize_random_table", Tensor{MEMORY_CPU, TYPE_BOOL, {1}, &is_initialize_random_table}}};
978	
979	                for (auto t = input_tensors->begin(); t != input_tensors->end(); ++t) {
980	                    if (dynamic_decode_input_tensors.find(t->first) == dynamic_decode_input_tensors.end()) {
981	                        dynamic_decode_input_tensors.insert(*t);
982	                    }
983	                }
984	
985	                // common outputs
986	                bool                                    subbatch_should_stop = false;
987	                std::unordered_map<std::string, Tensor> dynamic_decode_output_tensors{
988	                    {"output_ids",
989	                     Tensor{MEMORY_GPU, TYPE_INT32, {max_seq_len, batch_size, beam_width}, output_ids_buf_}},
990	                    {"finished", Tensor{MEMORY_GPU, TYPE_BOOL, {batch_size * beam_width}, finished_buf_}},
991	                    // cum_log_probs is necessary for beam search, while it is optional for sampling.
992	                    {"cum_log_probs",
993	                     Tensor{MEMORY_GPU,
994	                            TYPE_FP32,
995	                            {batch_size * beam_width},
996	                            ((beam_width > 1) || (output_tensors->count("cum_log_probs") > 0)) ? cum_log_probs_ :
997	                                                                                                 nullptr}},
998	                    {"output_log_probs",
999	                     Tensor{MEMORY_GPU,
1000	                            TYPE_FP32,
1001	                            {max_seq_len, batch_size, beam_width},
1002	                            output_tensors->count("output_log_probs") > 0
1003	                                    && output_tensors->at("output_log_probs").data != nullptr ?
1004	                                output_log_probs_buf_ :
1005	                                nullptr}},
1006	                    {"parent_ids",
1007	                     Tensor{MEMORY_GPU, TYPE_INT32, {max_seq_len, batch_size, beam_width}, parent_ids_buf_}},
1008	                    {"sequence_length", Tensor{MEMORY_GPU, TYPE_INT32, {batch_size * beam_width}, sequence_lengths_}},
1009	                    {"tgt_cache_indirection",
1010	                     Tensor{MEMORY_GPU,
1011	                            TYPE_INT32,
1012	                            {local_batch_size, beam_width, max_output_seq_len},
1013	                            cache_indirections_[tgt_indir_idx] + id_offset * max_output_seq_len}},
1014	                    {"should_stop", Tensor{MEMORY_CPU, TYPE_BOOL, {1}, &subbatch_should_stop}}};
1015	
1016	                for (auto t = output_tensors->begin(); t != output_tensors->end(); ++t) {
1017	                    // Handle exceptions.
1018	                    if (t->first == "cum_log_probs" || t->first == "output_log_probs") {
1019	                        continue;
1020	                    }
1021	                    dynamic_decode_output_tensors.insert(*t);
1022	                }
1023	
1024	                dynamic_decode_layer_->forward(&dynamic_decode_output_tensors, &dynamic_decode_input_tensors);
1025	                *generation_should_stop_ &= subbatch_should_stop;
1026	            }
1027	        }
1028	
1029	        if (pipeline_para_.world_size_ > 1) {
1030	            ftNcclGroupStart();
1031	            ftNcclBroadCast(output_ids_buf_ + step * batch_size * beam_width,
1032	                            batch_size * beam_width,
1033	                            pipeline_para_.world_size_ - 1,
1034	                            pipeline_para_,
1035	                            stream_);
1036	
1037	            ftNcclBroadCast(
1038	                sequence_lengths_, batch_size * beam_width, pipeline_para_.world_size_ - 1, pipeline_para_, stream_);
1039	
1040	            ftNcclBroadCast(generation_should_stop_, 1, pipeline_para_.world_size_ - 1, pipeline_para_, stream_);
1041	
1042	            if (beam_width > 1) {
1043	                ftNcclBroadCast(cache_indirections_[tgt_indir_idx],
1044	                                batch_size * beam_width * max_output_seq_len,
1045	                                pipeline_para_.world_size_ - 1,
1046	                                pipeline_para_,
1047	                                stream_);
1048	            }
1049	            ftNcclGroupEnd();
1050	            // throw errors when detected
1051	            ftNcclStreamSynchronize(tensor_para_, pipeline_para_, stream_);
1052	            sync_check_cuda_error();
1053	        }
1054	
1055	        if (*generation_should_stop_) {
1056	            break;
1057	        }
1058	        if (token_generated_cb_ && step + 1 < (int)max_output_seq_len) {
1059	            setOutputTensors(output_tensors, input_tensors, max_input_length, max_output_seq_len);
1060	            sendTensorsToFirstPipelineNode(output_tensors, input_tensors);
1061	
1062	            if (pipeline_para_.rank_ == 0 && tensor_para_.rank_ == 0) {
1063	                token_generated_cb_(output_tensors, token_generated_ctx_);
1064	            }
1065	        }
1066	        if (step == max_input_length) {
1067	            /* We have just finished processing input: update the padding count:
1068	             * total_padding_count += (max_input_length - input_lengths)
1069	             * if has prefix prompts, += (max_prefix_prompt_length - prompt_length)
1070	             */
1071	            invokeUpdatePaddingCount(tiled_total_padding_count_,
1072	                                     input_tensors->at("input_lengths").getPtr<const int>(),  // not_tiled
1073	                                     has_prefix_prompt_ ? tiled_prompt_lengths_buf_ : (const int*)nullptr,
1074	                                     max_input_length,
1075	                                     has_prefix_prompt_ ? max_prefix_prompt_length : 0,
1076	                                     batch_size,
1077	                                     beam_width,
1078	                                     stream_);
1079	        }
1080	    }
1081	    setOutputTensors(output_tensors, input_tensors, max_input_length, max_output_seq_len);
1082	    sendTensorsToFirstPipelineNode(output_tensors, input_tensors);
1083	}
1084	
1085	template<typename T>
1086	void GptJ<T>::sendTensorsToFirstPipelineNode(std::unordered_map<std::string, Tensor>*       output_tensors,
1087	                                             const std::unordered_map<std::string, Tensor>* input_tensors)
1088	{
1089	    FT_LOG_DEBUG("%s start", __PRETTY_FUNCTION__);
1090	    if (pipeline_para_.world_size_ == 1) {
1091	        // throw errors when detected
1092	        ftNcclStreamSynchronize(tensor_para_, pipeline_para_, stream_);
1093	        return;
1094	    }
1095	
1096	    const auto pp_rank = pipeline_para_.rank_;
1097	
1098	    ftNcclGroupStart();
1099	    for (auto const& it : *output_tensors) {
1100	        if (it.second.data == nullptr) {
1101	            continue;
1102	        }
1103	
1104	        if (pp_rank == pipeline_para_.world_size_ - 1) {
1105	            ftNcclSend(it.second.getPtr<char>(), it.second.sizeBytes(), 0, pipeline_para_, stream_);
1106	        }
1107	        else if (pp_rank == 0) {
1108	            ftNcclRecv(it.second.getPtr<char>(),
1109	                       it.second.sizeBytes(),
1110	                       pipeline_para_.world_size_ - 1,
1111	                       pipeline_para_,
1112	                       stream_);
1113	        }
1114	    }
1115	    ftNcclGroupEnd();
1116	    // throw errors when detected
1117	    ftNcclStreamSynchronize(tensor_para_, pipeline_para_, stream_);
1118	}
1119	
1120	template<typename T>
1121	void GptJ<T>::setOutputTensors(std::unordered_map<std::string, Tensor>*       output_tensors,
1122	                               const std::unordered_map<std::string, Tensor>* input_tensors,
1123	                               const size_t                                   max_input_length,
1124	                               const size_t                                   max_output_seq_len)
1125	{
1126	    FT_LOG_DEBUG("%s start", __PRETTY_FUNCTION__);
1127	    if (pipeline_para_.rank_ != pipeline_para_.world_size_ - 1) {
1128	        return;
1129	    }
1130	
1131	    const size_t batch_size       = output_tensors->at("output_ids").shape[0];
1132	    const size_t beam_width       = output_tensors->at("output_ids").shape[1];
1133	    int*         sequence_lengths = output_tensors->at("sequence_length").getPtr<int>();
1134	    const size_t max_prefix_soft_prompt_length =
1135	        has_prefix_soft_prompt_ ? input_tensors->at("request_prompt_embedding").shape[1] : 0;
1136	
1137	    cudaAutoCpy(sequence_lengths, sequence_lengths_, output_tensors->at("sequence_length").size(), stream_);
1138	    if (input_tensors->at("input_ids").shape[1] == 0) {
1139	        // TODO: D2D sequence_lenghts
1140	        if (beam_width > 1) {
1141	            // For beam search, do gather_tree
1142	            // take output_parent_ids as inter buffer
1143	            invokeGatherTree(transposed_output_ids_buf_,
1144	                             sequence_lengths_,
1145	                             max_output_seq_len,
1146	                             batch_size,
1147	                             beam_width,
1148	                             output_ids_buf_ + batch_size * beam_width,
1149	                             parent_ids_buf_ + batch_size * beam_width,
1150	                             end_ids_buf_,
1151	                             stream_);
1152	
1153	            // transpose and take output_parent_ids as inter buffer
1154	            invokeTransposeAxis01(output_tensors->at("output_ids").getPtr<int>(),
1155	                                  transposed_output_ids_buf_,
1156	                                  max_output_seq_len - 1,
1157	                                  batch_size * beam_width,
1158	                                  1,
1159	                                  stream_);
1160	        }
1161	        else {
1162	            // For sampling, only copy the results to output_tensor
1163	            invokeTransposeAxis01(output_tensors->at("output_ids").getPtr<int>(),
1164	                                  output_ids_buf_ + batch_size * beam_width,
1165	                                  max_output_seq_len - 1,
1166	                                  batch_size * beam_width,
1167	                                  1,
1168	                                  stream_);
1169	        }
1170	    }
1171	    else {
1172	        // For sampling, it is equivalent to all parent ids are 0.
1173	        gatherTreeParam param;
1174	        param.beams                = transposed_output_ids_buf_;
1175	        param.max_sequence_lengths = sequence_lengths;
1176	        // add sequence_length 1 here because the sequence_length of time step t is t - 1
1177	        param.max_sequence_length_final_step = 1;
1178	        param.max_time                       = max_output_seq_len;
1179	        param.batch_size                     = batch_size;
1180	        param.beam_width                     = beam_width;
1181	        param.step_ids                       = output_ids_buf_;
1182	        param.parent_ids                     = beam_width == 1 ? nullptr : parent_ids_buf_;
1183	        param.end_tokens                     = end_ids_buf_;
1184	        param.max_input_length               = max_input_length;
1185	        param.prefix_soft_prompt_lengths =
1186	            has_prefix_soft_prompt_ ? input_tensors->at("request_prompt_lengths").getPtr<int>() : nullptr;
1187	        param.input_lengths                   = tiled_input_lengths_buf_;
1188	        param.max_prefix_soft_prompt_length   = max_prefix_soft_prompt_length;
1189	        param.max_input_without_prompt_length = max_input_length;
1190	        param.stream                          = stream_;
1191	        param.output_ids                      = output_tensors->at("output_ids").getPtr<int>();
1192	        invokeGatherTree(param);
1193	        sync_check_cuda_error();
1194	    }
1195	    if ((output_tensors->count("output_log_probs") > 0 && output_tensors->at("output_log_probs").data != nullptr)) {
1196	        invokeTransposeAxis01(output_tensors->at("output_log_probs").getPtr<float>(),
1197	                              output_log_probs_buf_,
1198	                              input_tensors->at("output_seq_len").getVal<int>() - max_input_length,
1199	                              batch_size * beam_width,
1200	                              1,
1201	                              stream_);
1202	    }
1203	    // Return the cumulative log probability if requested.
1204	    if (output_tensors->count("cum_log_probs") > 0) {
1205	        Tensor cum_log_probs = output_tensors->at("cum_log_probs");
1206	        FT_CHECK_WITH_INFO(cum_log_probs.size() == batch_size * beam_width,
1207	                           "The shape of cum_log_probs does not match with batch_size x beam_width.");
1208	        cudaAutoCpy(cum_log_probs.getPtr<float>(), cum_log_probs_, cum_log_probs.size(), stream_);
1209	    }
1210	}
1211	
1212	template<typename T>
1213	size_t GptJ<T>::getPipelineParallelRank()
