65	    dynamic_decode_layer_ = new DynamicDecodeLayer<float>(vocab_size_,
66	                                                          vocab_size_padded_,
67	                                                          0,  // end_id, deprecated
68	                                                          stream_,
69	                                                          cublas_wrapper_,
70	                                                          allocator_,
71	                                                          is_free_buffer_after_forward_,
72	                                                          cuda_device_prop_);
73	}
