81	template<typename T>
82	void GptNeoX<T>::allocateBuffer(
83	    size_t batch_size, size_t beam_width, size_t max_seq_len, size_t max_cache_seq_len, size_t max_input_len)
84	{
85	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
86	    const size_t batchxbeam      = batch_size * beam_width;
87	    const size_t self_cache_size = (num_layer_ / pipeline_para_.world_size_) * batchxbeam * max_cache_seq_len
88	                                   * hidden_units_ / tensor_para_.world_size_;
89	
90	    if (vocab_size_ != vocab_size_padded_) {
91	        padded_embedding_kernel_ =
92	            (T*)(allocator_->reMalloc(padded_embedding_kernel_, sizeof(T) * hidden_units_ * vocab_size_padded_, true));
93	        padded_embedding_kernel_ptr_ = padded_embedding_kernel_;
94	
95	        padded_embedding_bias_ =
96	            (T*)(allocator_->reMalloc(padded_embedding_bias_, sizeof(T) * vocab_size_padded_, true));
97	    }
98	
99	    input_attention_mask_ = (T*)(allocator_->reMalloc(
100	        input_attention_mask_, sizeof(T) * batchxbeam * max_seq_len * max_cache_seq_len, false));
101	    decoder_input_buf_ = (T*)(allocator_->reMalloc(decoder_input_buf_, sizeof(T) * batchxbeam * hidden_units_, false));
102	    decoder_output_buf_ =
103	        (T*)(allocator_->reMalloc(decoder_output_buf_, sizeof(T) * batchxbeam * hidden_units_, false));
104	    normed_decoder_output_buf_ =
105	        (T*)(allocator_->reMalloc(normed_decoder_output_buf_, sizeof(T) * batchxbeam * hidden_units_, false));
106	    logits_buf_ = (float*)(allocator_->reMalloc(logits_buf_, sizeof(float) * batchxbeam * vocab_size_padded_, false));
107	    nccl_logits_buf_ =
108	        (float*)(allocator_->reMalloc(nccl_logits_buf_, sizeof(float) * batchxbeam * vocab_size_padded_, false));
109	    cum_log_probs_    = (float*)(allocator_->reMalloc(cum_log_probs_, sizeof(float) * batchxbeam, false));
110	    finished_buf_     = (bool*)(allocator_->reMalloc(finished_buf_, sizeof(bool) * batchxbeam, false));
111	    h_finished_buf_   = new bool[batchxbeam];
112	    sequence_lengths_ = (int*)(allocator_->reMalloc(sequence_lengths_, sizeof(int) * batchxbeam, false));
113	
114	    key_cache_   = (T*)(allocator_->reMalloc(key_cache_, sizeof(T) * self_cache_size * 2, true));
115	    value_cache_ = key_cache_ + self_cache_size;
116	    if (beam_width > 1) {
117	        cache_indirections_[0] =
118	            (int*)(allocator_->reMalloc(cache_indirections_[0], sizeof(int) * batchxbeam * max_seq_len * 2, true));
119	        cache_indirections_[1] = cache_indirections_[0] + batchxbeam * max_seq_len;
120	    }
121	
122	    // prompt_learning weight batch ptrs
123	    prompt_learning_weight_batch_ =
124	        (const T**)(allocator_->reMalloc(prompt_learning_weight_batch_, sizeof(T*) * batchxbeam, false));
125	    tiled_prompt_lengths_buf_ =
126	        (int*)(allocator_->reMalloc(tiled_prompt_lengths_buf_, sizeof(int) * batchxbeam, false));
127	
128	    tiled_input_ids_buf_ =
129	        (int*)(allocator_->reMalloc(tiled_input_ids_buf_, sizeof(int) * batchxbeam * max_input_len, true));
130	    tiled_input_lengths_buf_ = (int*)(allocator_->reMalloc(tiled_input_lengths_buf_, sizeof(int) * batchxbeam, true));
131	    tiled_total_padding_count_ =
132	        (int*)allocator_->reMalloc(tiled_total_padding_count_, batchxbeam * sizeof(int), false);
133	
134	    transposed_output_ids_buf_ =
135	        (int*)(allocator_->reMalloc(transposed_output_ids_buf_, sizeof(int) * batchxbeam * max_seq_len, true));
136	    output_ids_buf_ = (int*)(allocator_->reMalloc(output_ids_buf_, sizeof(int) * batchxbeam * max_seq_len, true));
137	    parent_ids_buf_ = (int*)(allocator_->reMalloc(parent_ids_buf_, sizeof(int) * batchxbeam * max_seq_len, true));
138	    seq_limit_len_  = (uint32_t*)(allocator_->reMalloc(seq_limit_len_, sizeof(uint32_t) * batch_size, false));
139	    masked_tokens_ = (bool*)(allocator_->reMalloc(masked_tokens_, sizeof(bool) * batchxbeam * max_cache_seq_len, true));
140	
141	    start_ids_buf_ = (int*)(allocator_->reMalloc(start_ids_buf_, sizeof(int) * batch_size, false));
142	    end_ids_buf_   = (int*)(allocator_->reMalloc(end_ids_buf_, sizeof(int) * batch_size, false));
143	
144	    context_decoder_input_buf_  = (T*)(allocator_->reMalloc(
145	        context_decoder_input_buf_, sizeof(T) * batchxbeam * max_input_len * hidden_units_, false));
146	    context_decoder_output_buf_ = (T*)(allocator_->reMalloc(
147	        context_decoder_output_buf_, sizeof(T) * batchxbeam * max_input_len * hidden_units_, false));
148	    output_log_probs_buf_ =
149	        (float*)(allocator_->reMalloc(output_log_probs_buf_, sizeof(float) * batchxbeam * max_seq_len, false));
150	
151	    generation_should_stop_ = (bool*)allocator_->reMalloc(generation_should_stop_, sizeof(bool), true, true);
152	
153	    is_allocate_buffer_ = true;
154	}
155	
156	template<typename T>
157	void GptNeoX<T>::freeBuffer()
158	{
159	    if (is_allocate_buffer_) {
160	        if (vocab_size_ != vocab_size_padded_) {
161	            padded_embedding_kernel_ptr_ = nullptr;
162	            allocator_->free((void**)(&padded_embedding_kernel_));
163	            allocator_->free((void**)(&padded_embedding_bias_));
164	        }
165	
166	        allocator_->free((void**)(&input_attention_mask_));
167	        allocator_->free((void**)(&decoder_input_buf_));
168	        allocator_->free((void**)(&decoder_output_buf_));
169	        allocator_->free((void**)(&normed_decoder_output_buf_));
170	        allocator_->free((void**)(&logits_buf_));
171	        allocator_->free((void**)(&nccl_logits_buf_));
172	        allocator_->free((void**)(&cum_log_probs_));
173	        allocator_->free((void**)(&finished_buf_));
174	        delete[] h_finished_buf_;
175	        allocator_->free((void**)(&sequence_lengths_));
176	
177	        allocator_->free((void**)(&key_cache_));
178	        if (cache_indirections_[0] != nullptr) {
179	            allocator_->free((void**)(&cache_indirections_)[0]);
180	        }
181	
182	        allocator_->free((void**)(&prompt_learning_weight_batch_));
183	        allocator_->free((void**)(&tiled_prompt_lengths_buf_));
184	
185	        allocator_->free((void**)(&tiled_input_ids_buf_));
186	        allocator_->free((void**)(&tiled_input_lengths_buf_));
187	        allocator_->free((void**)(&tiled_total_padding_count_));
188	
189	        allocator_->free((void**)(&transposed_output_ids_buf_));
190	        allocator_->free((void**)(&output_ids_buf_));
191	        allocator_->free((void**)(&parent_ids_buf_));
192	        allocator_->free((void**)(&seq_limit_len_));
193	        allocator_->free((void**)(&masked_tokens_));
194	
195	        allocator_->free((void**)(&start_ids_buf_));
196	        allocator_->free((void**)(&end_ids_buf_));
197	
198	        allocator_->free((void**)(&context_decoder_input_buf_));
199	        allocator_->free((void**)(&context_decoder_output_buf_));
200	        allocator_->free((void**)(&output_log_probs_buf_));
201	
202	        allocator_->free((void**)(&generation_should_stop_), true);
203	
204	        is_allocate_buffer_ = false;
205	    }
206	}
