377	
378	template<typename T>
379	void GptNeoX<T>::forward(std::unordered_map<std::string, Tensor>*       output_tensors,
380	                         const std::unordered_map<std::string, Tensor>* input_tensors,
381	                         const GptNeoXWeight<T>*                        gpt_weights)
382	{
383	    // input_tensors:
384	    //      input_ids [batch_size, max_input_length]
385	    //      input_lengths [batch_size]
386	    //      prompt_learning_task_name_ids [batch_size] on cpu, optional
387	    //      output_seq_len [batch_size] on cpu
388	    //      start_id [batch_size] on cpu, optional
389	    //      end_id [batch_size] on cpu, optional
390	    //      stop_words_list [batch_size, 2, stop_words_length], optional
391	    //      bad_words_list [2, bad_words_length] or [batch_size, 2, bad_words_length], optional
392	    //      runtime_top_k [1] or [batch_size] on cpu, optional, uint.
393	    //      runtime_top_p [1] or [batch_size] on cpu, optional, float.
394	    //      beam_search_diversity_rate [1] or [batch_size] on cpu, optional, float.
395	    //      temperature [1] or [batch_size] on cpu, optional, float.
396	    //      len_penalty [1] or [batch_size] on cpu, optional, float.
397	    //      repetition_penalty [1] or [batch_size] on cpu, optional, float.
398	    //      min_length [1] or [batch_size] on cpu, optional, int
399	    //      random_seed [1] or [batch_size] on cpu, optional, unsigned long long int.
400	    //      request_prompt_lengths [batch_size], optional
401	    //      request_prompt_embedding [batch_size, max_prompt_length, hidden_units], float, optional
402	    //      requst_prompt_type [batch_size], int, optional
403	    //      top_p_decay [batch_size] on gpu, float, optional
404	    //      top_p_min [batch_size] on gpu, float, optional
405	    //      top_p_reset_ids [batch_size] on gpu, uint32, optional
406	
407	    // output_tensors:
408	    //      output_ids [batch_size, beam_width, max_output_seq_len]
409	    //      sequence_length [batch_size, beam_width]
410	    //      output_log_probs [batch_size, beam_width, request_output_seq_len], must be float*.
411	    //          optional. It leads to additional computing cost. If we don't need this result, don't put it.
412	    //      cum_log_probs [batch_size, beam], optional, must be float*.
413	    //          optional. It leads to additional computing cost. If we don't need this result, don't put it.
414	
415	    // Step is from max_input_length ~ max_output_seq_len,
416	    // When step = k,  we put output ids and caches at step k, and the sequence_length would be k - 1 before
417	    // complete this step.
418	    // When there is no input_ids, put the start token at step 0 of output_ids_buf_. After forward, only copy
419	    // the step 1 ~ max_output_seq_len of output_ids_buf_ to output_tensors->at(0).data
420	
421	    FT_CHECK_WITH_INFO(input_tensors->size() >= 3, "input_tensors->size() >= 3");
422	    FT_CHECK_WITH_INFO(output_tensors->size() >= 2, "output_tensors->size() >= 2");
423	    FT_CHECK(input_tensors->at("input_ids").shape.size() == 2);
424	    FT_CHECK(input_tensors->at("input_lengths").shape.size() == 1);
425	    FT_CHECK(input_tensors->find("output_seq_len") != input_tensors->end()
426	             && input_tensors->at("output_seq_len").shape.size() == 1);
427	    FT_CHECK(output_tensors->at("output_ids").shape.size() == 3);
428	    FT_CHECK(output_tensors->at("sequence_length").shape.size() == 2);
429	    FT_CHECK_WITH_INFO(input_tensors->at("input_ids").shape[0] == output_tensors->at("output_ids").shape[0],
430	                       "input_tensors->at(\"input_ids\").shape[0] == output_tensors->at(\"output_ids\").shape[0]");
431	
432	    const size_t batch_size = output_tensors->at("output_ids").shape[0];
433	    const size_t beam_width = output_tensors->at("output_ids").shape[1];
434	
435	    PromptLearningType request_prompt_type = PromptLearningType::no_prompt;
436	    int                valid_prompt_inputs = input_tensors->count("request_prompt_type")
437	                              + input_tensors->count("request_prompt_lengths")
438	                              + input_tensors->count("request_prompt_embedding");
439	
440	    if (valid_prompt_inputs == 3) {
441	        request_prompt_type = static_cast<PromptLearningType>(input_tensors->at("request_prompt_type").getVal<int>());
442	        FT_LOG_INFO("Apply prompt embedding from input, will ignore task name ids");
443	    }
444	    else if (valid_prompt_inputs > 0) {
445	        FT_LOG_WARNING(
446	            "Prompts not applied: request_prompt_embedding, request_prompt_lengths, request_prompt_type are all needed!");
447	    }
448	    if (request_prompt_type == PromptLearningType::prefix_prompt) {
449	        FT_LOG_WARNING("Request prompt doesn't support prefix prompt currently!");
450	    }
451	
452	    // Prefix Prompt Inputs
453	    // Padding works as follows: p p x x i i i x x --> p p i i i x x x x (p denotes prompt, i denotes input, x denotes
454	    // pad)
455	    // TODO (perkzz): move unnecessary paddings
456	    const int* prompt_learning_task_name_ids =
457	        input_tensors->count("prompt_learning_task_name_ids") ?
458	            input_tensors->at("prompt_learning_task_name_ids").getPtr<const int>() :
459	            nullptr;
460	    has_prefix_prompt_ =
461	        (prompt_learning_task_name_ids != nullptr) && (prompt_learning_type_ == PromptLearningType::prefix_prompt);
462	    int max_prefix_prompt_length = 0;
463	
464	    FT_CHECK_WITH_INFO(
465	        !(prompt_learning_task_name_ids != nullptr
466	          && (prompt_learning_type_ == PromptLearningType::no_prompt
467	              || prompt_learning_type_ == PromptLearningType::soft_prompt)),
468	        "prompt_learning_type is prefix_prompt either p_prompt_tuning when prompt_learning_task_name_ids are provided.");
469	
470	    // NOTE: Prefix Prompt PreProcessing
471	    // get prefix_prompt_weight for each batch --> shape [batch, beam_width]
472	    // --> ptrs with shape [num_layers, 2, num_heads, perfix_seq_len, size_per_head]
473	    std::vector<const T*> prefix_prompt_weight_batch_ptrs;
474	    std::vector<int>      prefix_prompt_lengths;
475	    if (has_prefix_prompt_) {
476	        for (int bs_id = 0; bs_id < batch_size; ++bs_id) {
477	            int task_id = prompt_learning_task_name_ids[bs_id];
478	            // throw errors when prompt task_name_ids are not found
479	            std::pair<const T*, int> prefix_prompt_weight_length_pair;
480	            try {
481	                prefix_prompt_weight_length_pair = gpt_weights->prompt_learning_table.at(task_id);
482	            }
483	            catch (const std::out_of_range& oor) {
484	                FT_LOG_ERROR("prefix_prompt_weights_lengths not found for prompt task id: " + task_id);
485	                throw oor;
486	            }
487	            for (int bw_id = 0; bw_id < beam_width; ++bw_id) {
488	                prefix_prompt_weight_batch_ptrs.push_back(prefix_prompt_weight_length_pair.first);
489	                prefix_prompt_lengths.push_back(prefix_prompt_weight_length_pair.second);
490	            }
491	        }
492	
493	        max_prefix_prompt_length = *max_element(prefix_prompt_lengths.begin(), prefix_prompt_lengths.end());
494	
495	        FT_LOG_DEBUG("max_prefix_prompt_length: %d", max_prefix_prompt_length);
496	
497	        if (max_prefix_prompt_length == 0) {
498	            has_prefix_prompt_ = false;
499	            FT_LOG_DEBUG("prompts are not applied !");
500	        }
501	    }
502	
503	    int max_input_length = input_tensors->at("input_ids").shape[1];
504	    FT_CHECK_WITH_INFO(!(max_input_length == 0 && max_prefix_prompt_length > 0),
505	                       "Prefix Prompt should come with inputs!");
506	
507	    // Prefix Soft Prompt
