973	                            {local_batch_size, beam_width, max_output_seq_len},
974	                            cache_indirections_[tgt_indir_idx] + id_offset * max_output_seq_len}},
975	                    {"should_stop", Tensor{MEMORY_CPU, TYPE_BOOL, {1}, &subbatch_should_stop}}};
976	
977	                for (auto t = output_tensors->begin(); t != output_tensors->end(); ++t) {
978	                    // Handle exceptions.
979	                    if (t->first == "cum_log_probs" || t->first == "output_log_probs") {
980	                        continue;
981	                    }
982	                    dynamic_decode_output_tensors.insert(*t);
983	                }
984	
985	                dynamic_decode_layer_->forward(&dynamic_decode_output_tensors, &dynamic_decode_input_tensors);
986	                *generation_should_stop_ &= subbatch_should_stop;
987	            }
988	        }
989	
990	        if (pipeline_para_.world_size_ > 1) {
991	            ftNcclGroupStart();
992	            ftNcclBroadCast(output_ids_buf_ + step * batch_size * beam_width,
993	                            batch_size * beam_width,
994	                            pipeline_para_.world_size_ - 1,
995	                            pipeline_para_,
996	                            stream_);
997	
998	            ftNcclBroadCast(
999	                sequence_lengths_, batch_size * beam_width, pipeline_para_.world_size_ - 1, pipeline_para_, stream_);
1000	
1001	            ftNcclBroadCast(generation_should_stop_, 1, pipeline_para_.world_size_ - 1, pipeline_para_, stream_);
1002	
1003	            if (beam_width > 1) {
1004	                ftNcclBroadCast(cache_indirections_[tgt_indir_idx],
1005	                                batch_size * beam_width * max_output_seq_len,
1006	                                pipeline_para_.world_size_ - 1,
1007	                                pipeline_para_,
1008	                                stream_);
1009	            }
1010	            ftNcclGroupEnd();
1011	            // throw errors when detected
1012	            ftNcclStreamSynchronize(tensor_para_, pipeline_para_, stream_);
1013	            sync_check_cuda_error();
1014	        }
1015	
1016	        if (*generation_should_stop_) {
1017	            break;
1018	        }
1019	        if (token_generated_cb_ && step + 1 < (int)max_output_seq_len) {
1020	            setOutputTensors(output_tensors, input_tensors, max_input_length, max_output_seq_len);
1021	            sendTensorsToFirstPipelineNode(output_tensors, input_tensors);
1022	
1023	            if (pipeline_para_.rank_ == 0 && tensor_para_.rank_ == 0) {
1024	                token_generated_cb_(output_tensors, token_generated_ctx_);
1025	            }
1026	        }
1027	        if (step == max_input_length) {
1028	            /* We have just finished processing input: update the padding count:
1029	             * total_padding_count += (max_input_length - input_lengths)
1030	             * if has prefix prompts, += (max_prefix_prompt_length - prompt_length)
1031	             */
1032	            invokeUpdatePaddingCount(tiled_total_padding_count_,
1033	                                     input_tensors->at("input_lengths").getPtr<const int>(),  // not_tiled
1034	                                     has_prefix_prompt_ ? tiled_prompt_lengths_buf_ : (const int*)nullptr,
1035	                                     max_input_length,
1036	                                     has_prefix_prompt_ ? max_prefix_prompt_length : 0,
1037	                                     batch_size,
1038	                                     beam_width,
1039	                                     stream_);
1040	        }
1041	    }
1042	
1043	    setOutputTensors(output_tensors, input_tensors, max_input_length, max_output_seq_len);
1044	    sendTensorsToFirstPipelineNode(output_tensors, input_tensors);
1045	}
1046	
1047	template<typename T>
1048	void GptNeoX<T>::sendTensorsToFirstPipelineNode(std::unordered_map<std::string, Tensor>*       output_tensors,
1049	                                                const std::unordered_map<std::string, Tensor>* input_tensors)
1050	{
1051	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
1052	    if (pipeline_para_.world_size_ == 1) {
1053	        // throw errors when detected
1054	        ftNcclStreamSynchronize(tensor_para_, pipeline_para_, stream_);
1055	        return;
1056	    }
1057	
1058	    const auto pp_rank = pipeline_para_.rank_;
1059	
1060	    ftNcclGroupStart();
1061	    for (auto const& it : *output_tensors) {
1062	        if (it.second.data == nullptr) {
1063	            continue;
1064	        }
1065	
1066	        if (pp_rank == pipeline_para_.world_size_ - 1) {
1067	            ftNcclSend(it.second.getPtr<char>(), it.second.sizeBytes(), 0, pipeline_para_, stream_);
1068	        }
1069	        else if (pp_rank == 0) {
1070	            ftNcclRecv(it.second.getPtr<char>(),
1071	                       it.second.sizeBytes(),
1072	                       pipeline_para_.world_size_ - 1,
1073	                       pipeline_para_,
1074	                       stream_);
1075	        }
1076	    }
1077	    ftNcclGroupEnd();
1078	    // throw errors when detected
1079	    ftNcclStreamSynchronize(tensor_para_, pipeline_para_, stream_);
1080	}
1081	
1082	template<typename T>
1083	void GptNeoX<T>::setOutputTensors(std::unordered_map<std::string, Tensor>*       output_tensors,
1084	                                  const std::unordered_map<std::string, Tensor>* input_tensors,
1085	                                  const size_t                                   max_input_length,
1086	                                  const size_t                                   max_output_seq_len)
1087	{
1088	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
1089	    if (pipeline_para_.rank_ != pipeline_para_.world_size_ - 1) {
1090	        return;
1091	    }
1092	
1093	    const size_t batch_size       = output_tensors->at("output_ids").shape[0];
1094	    const size_t beam_width       = output_tensors->at("output_ids").shape[1];
1095	    uint*        sequence_lengths = output_tensors->at("sequence_length").getPtr<uint>();
1096	    const size_t max_prefix_soft_prompt_length =
1097	        has_prefix_soft_prompt_ ? input_tensors->at("request_prompt_embedding").shape[1] : 0;
1098	
1099	    if (input_tensors->at("input_ids").shape[1] == 0) {
1100	        invokeCudaD2DcpyConvert(
1101	            sequence_lengths, sequence_lengths_, output_tensors->at("sequence_length").size(), stream_);
1102	        // TODO: D2D sequence_lenghts
1103	        if (beam_width > 1) {
1104	            // For beam search, do gather_tree
1105	            // take output_parent_ids as inter buffer
1106	            invokeGatherTree(transposed_output_ids_buf_,
1107	                             sequence_lengths_,
1108	                             max_output_seq_len,
1109	                             batch_size,
1110	                             beam_width,
1111	                             output_ids_buf_ + batch_size * beam_width,
1112	                             parent_ids_buf_ + batch_size * beam_width,
1113	                             end_ids_buf_,
1114	                             stream_);
1115	
1116	            // transpose and take output_parent_ids as inter buffer
1117	            invokeTransposeAxis01(output_tensors->at("output_ids").getPtr<int>(),
1118	                                  transposed_output_ids_buf_,
1119	                                  max_output_seq_len - 1,
1120	                                  batch_size * beam_width,
1121	                                  1,
1122	                                  stream_);
1123	        }
1124	        else {
1125	            // For sampling, only copy the results to output_tensor
1126	            invokeTransposeAxis01(output_tensors->at("output_ids").getPtr<int>(),
1127	                                  output_ids_buf_ + batch_size * beam_width,
1128	                                  max_output_seq_len - 1,
1129	                                  batch_size * beam_width,
1130	                                  1,
1131	                                  stream_);
1132	        }
1133	    }
1134	    else {
1135	
1136	        // For sampling, it is equivalent to all parent ids are 0.
1137	        gatherTreeParam param;
1138	        param.beams                = transposed_output_ids_buf_;
1139	        param.max_sequence_lengths = sequence_lengths_;
1140	        // add sequence_length 1 here because the sequence_length of time step t is t - 1
1141	        param.max_sequence_length_final_step = 1;
1142	        param.max_time                       = max_output_seq_len;
1143	        param.batch_size                     = batch_size;
1144	        param.beam_width                     = beam_width;
1145	        param.step_ids                       = output_ids_buf_;
1146	        param.parent_ids                     = beam_width == 1 ? nullptr : parent_ids_buf_;
1147	        param.end_tokens                     = end_ids_buf_;
1148	        param.max_input_length               = max_input_length;
1149	        param.prefix_soft_prompt_lengths =
1150	            has_prefix_soft_prompt_ ? input_tensors->at("request_prompt_lengths").getPtr<int>() : nullptr;
1151	        param.input_lengths                   = tiled_input_lengths_buf_;
1152	        param.max_prefix_soft_prompt_length   = max_prefix_soft_prompt_length;
1153	        param.max_input_without_prompt_length = max_input_length;
1154	        param.stream                          = stream_;
1155	        param.output_ids                      = output_tensors->at("output_ids").getPtr<int>();
1156	        invokeGatherTree(param);
1157	        invokeCudaD2DcpyConvert(
1158	            sequence_lengths, sequence_lengths_, output_tensors->at("sequence_length").size(), stream_);
1159	        sync_check_cuda_error();
1160	    }
1161	    if ((output_tensors->count("output_log_probs") > 0 && output_tensors->at("output_log_probs").data != nullptr)) {
1162	        invokeTransposeAxis01(output_tensors->at("output_log_probs").getPtr<float>(),
1163	                              output_log_probs_buf_,
1164	                              input_tensors->at("output_seq_len").max<uint32_t>() - max_input_length,
1165	                              batch_size * beam_width,
1166	                              1,
1167	                              stream_);
1168	    }
1169	    // Return the cumulative log probability if requested.
1170	    if (output_tensors->count("cum_log_probs") > 0) {
1171	        Tensor cum_log_probs = output_tensors->at("cum_log_probs");
1172	        FT_CHECK_WITH_INFO(cum_log_probs.size() == batch_size * beam_width,
1173	                           "The shape of cum_log_probs does not match with batch_size x beam_width.");
1174	        cudaAutoCpy(cum_log_probs.getPtr<float>(), cum_log_probs_, cum_log_probs.size(), stream_);
1175	    }
1176	}
1177	
1178	template<typename T>
1179	size_t GptNeoX<T>::getPipelineParallelRank()
1180	{
1181	    return pipeline_para_.rank_;
1182	}
1183	
1184	template<typename T>
1185	size_t GptNeoX<T>::getPipelineParallelSize()
1186	{
1187	    return pipeline_para_.world_size_;
1188	}
1189	
1190	template<typename T>
1191	size_t GptNeoX<T>::getTensorParallelRank()
1192	{
1193	    return tensor_para_.rank_;
1194	}
1195	
1196	template<typename T>
1197	size_t GptNeoX<T>::getTensorParallelSize()
1198	{
1199	    return tensor_para_.world_size_;
1200	}
1201	
1202	template<typename T>
1203	bool* GptNeoX<T>::getFinishBuffer()
1204	{
1205	    return finished_buf_;
1206	}
