62	
63	template<typename T>
64	void BartDecoding<T>::allocateBuffer(
65	    size_t batch_size, size_t beam_width, size_t max_seq_len, size_t max_mem_seq_len, size_t encoder_d_model)
66	{
67	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
68	    // Note: To put the start_ids, we use max_seq_len + 1 for ouptut_ids_buf_
69	    // And to consistent to the output_ids_buf_, some related buffers are also
70	    // use max_seq_len + 1, but not max_seq_len.
71	    // This only affects the buffer size, not affect the performance.
72	
73	    const size_t batchxbeam      = batch_size * beam_width;
74	    const size_t self_cache_size = (num_layer_ / pipeline_para_.world_size_) * batchxbeam * (max_seq_len + 1)
75	                                   * (hidden_units_ / tensor_para_.world_size_);
76	    const size_t mem_cache_size = (num_layer_ / pipeline_para_.world_size_) * batchxbeam * max_mem_seq_len
77	                                  * (hidden_units_ / tensor_para_.world_size_);
78	
79	    if (vocab_size_ != vocab_size_padded_) {
80	        padded_embedding_kernel_ =
81	            (T*)(allocator_->reMalloc(padded_embedding_kernel_, sizeof(T) * d_model_ * vocab_size_padded_, true));
82	        padded_embedding_kernel_ptr_ = padded_embedding_kernel_;
83	
84	        padded_post_decoder_embedding_bias_ =
85	            (T*)(allocator_->reMalloc(padded_post_decoder_embedding_bias_, sizeof(T) * vocab_size_padded_, true));
86	        padded_post_decoder_embedding_bias_ptr_ = padded_post_decoder_embedding_bias_;
87	    }
88	    relative_attention_bias_ = (T*)(allocator_->reMalloc(
89	        relative_attention_bias_, sizeof(T) * head_num_ * (max_seq_len + 1) * (max_seq_len + 1), false));
90	
91	    decoder_input_buf_  = (T*)(allocator_->reMalloc(decoder_input_buf_, sizeof(T) * batchxbeam * d_model_, false));
92	    decoder_output_buf_ = (T*)(allocator_->reMalloc(decoder_output_buf_, sizeof(T) * batchxbeam * d_model_, false));
93	    normed_decoder_output_buf_ =
94	        (T*)(allocator_->reMalloc(normed_decoder_output_buf_, sizeof(T) * batchxbeam * d_model_, false));
95	    logits_buf_      = (DynamicDecodeType*)(allocator_->reMalloc(
96	        logits_buf_, sizeof(DynamicDecodeType) * batchxbeam * vocab_size_padded_, false));
97	    nccl_logits_buf_ = (DynamicDecodeType*)(allocator_->reMalloc(
98	        nccl_logits_buf_, sizeof(DynamicDecodeType) * batchxbeam * vocab_size_padded_, false));
99	    cum_log_probs_   = (float*)(allocator_->reMalloc(cum_log_probs_, sizeof(float) * batchxbeam, false));
100	    finished_buf_    = (bool*)(allocator_->reMalloc(finished_buf_, sizeof(bool) * batchxbeam, false));
101	    h_finished_buf_  = (bool*)realloc(h_finished_buf_, sizeof(bool) * batchxbeam);
102	
103	    key_cache_ = (T*)(allocator_->reMalloc(key_cache_, sizeof(T) * (2 * self_cache_size + 2 * mem_cache_size), false));
104	    value_cache_     = key_cache_ + self_cache_size;
105	    key_mem_cache_   = value_cache_ + self_cache_size;
106	    value_mem_cache_ = key_mem_cache_ + mem_cache_size;
107	    if (beam_width > 1) {
108	        cache_indirections_[0] = (int*)(allocator_->reMalloc(
109	            cache_indirections_[0], sizeof(int) * batchxbeam * (max_seq_len + 1) * 2, true));
110	        cache_indirections_[1] = cache_indirections_[0] + batchxbeam * (max_seq_len + 1);
111	    }
112	    tiled_encoder_output_ = (T*)(allocator_->reMalloc(
113	        tiled_encoder_output_, sizeof(T) * batchxbeam * max_mem_seq_len * encoder_d_model, false));
114	    tiled_encoder_sequence_length_ =
115	        (int*)(allocator_->reMalloc(tiled_encoder_sequence_length_, sizeof(int) * batchxbeam, false));
116	
117	    start_ids_buf_ = (int*)(allocator_->reMalloc(start_ids_buf_, sizeof(int) * batch_size, false));
118	    end_ids_buf_   = (int*)(allocator_->reMalloc(end_ids_buf_, sizeof(int) * batch_size, false));
119	
120	    output_ids_buf_ =
121	        (int*)(allocator_->reMalloc(output_ids_buf_, sizeof(int) * batchxbeam * (max_seq_len + 1), false));
122	    parent_ids_buf_ =
123	        (int*)(allocator_->reMalloc(parent_ids_buf_, sizeof(int) * batchxbeam * (max_seq_len + 1), false));
124	    output_ids_transpose_buf_ =
125	        (int*)(allocator_->reMalloc(output_ids_transpose_buf_, sizeof(int) * batchxbeam * (max_seq_len + 1), false));
126	    output_log_probs_buf_ =
127	        (float*)(allocator_->reMalloc(output_log_probs_buf_, sizeof(float) * batchxbeam * (max_seq_len + 1), false));
128	
129	    if (using_beam_hyps) {
130	        // Let beam_hyps_ can record at most 2*beam_width because we
131	        // may find beam_width finished candidates during generation,
132	        // and may compare them with unfinifhsed another beam_width candidates
133	        // during finalization.
134	        beam_hyps_.output_ids_tgt = (int*)allocator_->reMalloc(
135	            beam_hyps_.output_ids_tgt, sizeof(int) * batch_size * beam_width * 2 * (max_seq_len + 1), true);
136	        beam_hyps_.sequence_lengths_tgt = (int*)allocator_->reMalloc(
137	            beam_hyps_.sequence_lengths_tgt, sizeof(int) * batch_size * beam_width * 2, true);
138	        beam_hyps_.cum_log_probs =
139	            (float*)allocator_->reMalloc(beam_hyps_.cum_log_probs, sizeof(float) * batch_size * beam_width * 2, true);
140	        beam_hyps_.normed_scores =
141	            (float*)allocator_->reMalloc(beam_hyps_.normed_scores, sizeof(float) * batch_size * beam_width * 2, true);
142	        beam_hyps_.log_probs = (float*)allocator_->reMalloc(
143	            beam_hyps_.log_probs, sizeof(float) * batch_size * beam_width * 2 * (max_seq_len + 1), true);
144	        beam_hyps_.min_normed_scores =
145	            (float*)allocator_->reMalloc(beam_hyps_.min_normed_scores, sizeof(float) * batch_size, true);
146	        beam_hyps_.num_beams = (int*)allocator_->reMalloc(beam_hyps_.num_beams, sizeof(int) * batch_size, true);
147	        beam_hyps_.is_done   = (bool*)allocator_->reMalloc(beam_hyps_.is_done, sizeof(bool) * batch_size, true);
148	    }
149	    is_allocate_buffer_ = true;
150	}
