152	template<typename T>
153	void BartDecoding<T>::freeBuffer()
154	{
155	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
156	    if (is_allocate_buffer_) {
157	        if (vocab_size_ != vocab_size_padded_) {
158	            padded_embedding_kernel_ptr_ = nullptr;
159	            allocator_->free((void**)(&padded_embedding_kernel_));
160	
161	            padded_post_decoder_embedding_bias_ptr_ = nullptr;
162	            allocator_->free((void**)(&padded_post_decoder_embedding_bias_));
163	        }
164	
165	        allocator_->free((void**)(&relative_attention_bias_));
166	
167	        allocator_->free((void**)(&decoder_input_buf_));
168	        allocator_->free((void**)(&decoder_output_buf_));
169	        allocator_->free((void**)(&normed_decoder_output_buf_));
170	        allocator_->free((void**)(&logits_buf_));
171	        allocator_->free((void**)(&nccl_logits_buf_));
172	        allocator_->free((void**)(&cum_log_probs_));
173	        allocator_->free((void**)(&finished_buf_));
174	        free(h_finished_buf_);
175	
176	        allocator_->free((void**)(&key_cache_));
177	        if (cache_indirections_[0] != nullptr) {
178	            allocator_->free((void**)(&cache_indirections_)[0]);
179	        }
180	
181	        allocator_->free((void**)(&tiled_encoder_output_));
182	        allocator_->free((void**)(&tiled_encoder_sequence_length_));
183	
184	        allocator_->free((void**)(&start_ids_buf_));
185	        allocator_->free((void**)(&end_ids_buf_));
186	
187	        allocator_->free((void**)(&output_ids_buf_));
188	        allocator_->free((void**)(&parent_ids_buf_));
189	        allocator_->free((void**)(&output_ids_transpose_buf_));
190	        allocator_->free((void**)(&output_log_probs_buf_));
191	
192	        if (using_beam_hyps) {
193	            allocator_->free((void**)(&beam_hyps_.output_ids_tgt));
194	            allocator_->free((void**)(&beam_hyps_.sequence_lengths_tgt));
195	            allocator_->free((void**)(&beam_hyps_.cum_log_probs));
196	            allocator_->free((void**)(&beam_hyps_.normed_scores));
197	            allocator_->free((void**)(&beam_hyps_.log_probs));
198	            allocator_->free((void**)(&beam_hyps_.min_normed_scores));
199	            allocator_->free((void**)(&beam_hyps_.num_beams));
200	            allocator_->free((void**)(&beam_hyps_.is_done));
201	        }
202	        is_allocate_buffer_ = false;
203	    }
204	}
