324	template<typename T>
325	void BartDecoding<T>::forward(TensorMap*                   output_tensors,
326	                              TensorMap*                   input_tensors,
327	                              const BartDecodingWeight<T>* decoding_weights)
328	{
329	    // input_tensors:
330	    //      encoder_output [batch_size, mem_max_seq_len, memory_hidden_dimension]
331	    //      encoder_sequence_length [batch_size]
332	    //      stop_words_list [batch_size, 2, stop_words_length], optional
333	    //      bad_words_list [batch_size, 2, stop_words_length], optional
334	    //      start_id [batch_size] on cpu, optional
335	    //      end_id [batch_size] on cpu, optional
336	    //      runtime_top_k [1] or [batch_size] on cpu, optional, uint.
337	    //      runtime_top_p [1] or [batch_size] on cpu, optional, float.
338	    //      beam_search_diversity_rate [1] or [batch_size] on cpu, optional, float.
339	    //      temperature [1] or [batch_size] on cpu, optional, float.
340	    //      len_penalty [1] or [batch_size] on cpu, optional, float.
341	    //      repetition_penalty [1] or [batch_size] on cpu, optional, float.
342	    //      random_seed [1] or [batch_size] on cpu, optional, unsigned long long int.
343	    //      top_p_decay [batch_size] on gpu, float, optional
344	    //      top_p_min [batch_size] on gpu, float, optional
345	    //      top_p_reset_ids [batch_size] on gpu, uint32, optional
346	
347	    // output_tensors:
348	    //      output_ids [batch_size, beam, max_seq_len]
349	    //      sequence_length [batch_size, beam], record the number of generated token, except the start token
350	    //      output_log_probs [batch_size, beam, max_seq_len], optional, must be float*.
351	    //      cum_log_probs [batch_size, beam], optional, must be float*.
352	    //      cross_attentions [num_layer / pipeline_para_size, batch_size, beam,
353	    //         head_num / tensor_para_size, max_seq_len, mem_max_seq_len], optional, must be float*.
354	
355	    // Step is from 1 ~ max_seq_len,
356	    // When step = k,  we put output ids and caches at step k, and the sequence_length would be k - 1 before
357	    // complete this step.
358	
359	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
360	    FT_CHECK(input_tensors->size() >= 2);
361	    FT_CHECK(output_tensors->size() >= 2);
362	    FT_CHECK(input_tensors->at("encoder_output").shape.size() == 3);
363	    const size_t batch_size      = output_tensors->at("output_ids").shape[0];
364	    const size_t beam_width      = output_tensors->at("output_ids").shape[1];
365	    const size_t max_seq_len     = output_tensors->at("output_ids").shape[2];
366	    const size_t mem_max_seq_len = input_tensors->at("encoder_output").shape[1];
367	    allocateBuffer(batch_size, beam_width, max_seq_len, mem_max_seq_len, input_tensors->at("encoder_output").shape[2]);
368	
369	    {
370	        TensorMap input_map(*input_tensors);
371	        dynamic_decode_layer_->setup(batch_size, beam_width, &input_map);
372	        handleOptArg(&input_map, "start_id", start_ids_buf_, start_id_, batch_size);
373	        handleOptArg(&input_map, "end_id", end_ids_buf_, end_id_, batch_size);
374	    }
375	
376	    FT_CHECK_WITH_INFO(input_tensors->at("encoder_output").shape[2] == d_model_,
377	                       fmtstr("expect input_tensors->at(\"encoder_output\").shape[2] == d_model_, "
378	                              "but get input_tensors->at(\"encoder_output\").shape[2] = %d, d_model_ = %d",
379	                              input_tensors->at("encoder_output").shape[2],
380	                              d_model_));
381	
382	    const int      max_input_length = 1;
383	    const DataType data_type        = getTensorType<T>();
384	    int*           sequence_lengths = output_tensors->at("sequence_length").getPtr<int>();
385	
386	    cudaMemsetAsync(
387	        output_tensors->at("output_ids").getPtr<int>(), 0, output_tensors->at("output_ids").sizeBytes(), stream_);
388	    cudaMemsetAsync(output_ids_buf_, 0, sizeof(int) * batch_size * beam_width * (max_seq_len + 1), stream_);
389	    cudaMemsetAsync(parent_ids_buf_, 0, sizeof(int) * batch_size * beam_width * (max_seq_len + 1), stream_);
390	    if (beam_width > 1) {
391	        cudaMemsetAsync(
392	            cache_indirections_[0], 0, 2 * sizeof(int) * batch_size * beam_width * (max_seq_len + 1), stream_);
393	    }
394	
395	    if (beam_width > 1) {
396	        invokeTileEncoderResults(tiled_encoder_output_,
397	                                 tiled_encoder_sequence_length_,
398	                                 input_tensors->at("encoder_output").getPtr<T>(),
399	                                 input_tensors->at("encoder_sequence_length").getPtr<const int>(),
400	                                 batch_size,
401	                                 beam_width,
402	                                 mem_max_seq_len,
403	                                 d_model_,
404	                                 stream_);
405	        sync_check_cuda_error();
406	        encoder_output_ptr_          = tiled_encoder_output_;
407	        encoder_sequence_length_ptr_ = tiled_encoder_sequence_length_;
408	    }
409	    else {
410	        encoder_output_ptr_          = input_tensors->at("encoder_output").getPtr<const T>();
411	        encoder_sequence_length_ptr_ = input_tensors->at("encoder_sequence_length").getPtr<const int>();
412	    }
413	
414	    invokeDecodingInitialize(finished_buf_,
415	                             sequence_lengths,
416	                             output_ids_buf_,
417	                             cum_log_probs_,
418	                             start_ids_buf_,
419	                             batch_size,
420	                             beam_width,
421	                             max_input_length - 1,
422	                             stream_);
423	    sync_check_cuda_error();
424	
425	    invokeBuildRelativeAttentionBias(relative_attention_bias_,
426	                                     decoding_weights->absolute_or_relative_position_embedding,
427	                                     head_num_,
428	                                     (max_seq_len + 1),
429	                                     num_bucket_,
430	                                     false,
431	                                     max_distance_,
432	                                     decoding_weights->position_embedding_type,
433	                                     stream_);
434	    sync_check_cuda_error();
435	
436	    if (vocab_size_ == vocab_size_padded_) {
437	        padded_embedding_kernel_ptr_            = decoding_weights->post_decoder_embedding.kernel;
438	        padded_post_decoder_embedding_bias_ptr_ = decoding_weights->post_decoder_embedding.bias;
439	    }
440	    else {
441	        invokePaddingEmbeddingKernel(padded_embedding_kernel_,
442	                                     decoding_weights->post_decoder_embedding.kernel,
443	                                     d_model_,
444	                                     vocab_size_,
445	                                     vocab_size_padded_,
446	                                     stream_);
447	        sync_check_cuda_error();
448	        if (decoding_weights->post_decoder_embedding.bias != nullptr) {
449	            cudaAutoCpy(padded_post_decoder_embedding_bias_,
450	                        decoding_weights->post_decoder_embedding.bias,
451	                        vocab_size_,
452	                        stream_);
453	        }
454	    }
455	
456	    const std::vector<size_t> self_k_cache_shape = {num_layer_ / pipeline_para_.world_size_,
457	                                                    batch_size * beam_width,
458	                                                    head_num_ / tensor_para_.world_size_,
459	                                                    size_per_head_ / (16 / sizeof(T)),
460	                                                    max_seq_len + 1,
461	                                                    16 / sizeof(T)};
462	    const std::vector<size_t> self_v_cache_shape = {num_layer_ / pipeline_para_.world_size_,
463	                                                    batch_size * beam_width,
464	                                                    head_num_ / tensor_para_.world_size_,
465	                                                    (size_t)(max_seq_len + 1),
466	                                                    size_per_head_};
467	    const std::vector<size_t> mem_cache_shape    = {num_layer_ / pipeline_para_.world_size_,
468	                                                    batch_size * beam_width,
469	                                                    mem_max_seq_len,
470	                                                    head_num_ / tensor_para_.world_size_ * size_per_head_};
471	
472	    const size_t local_batch_size = getLocalBatchSize(batch_size, 1, pipeline_para_.world_size_);
473	    FT_CHECK(batch_size % local_batch_size == 0);
474	    const size_t iteration_num = batch_size / local_batch_size;
475	    for (int step = max_input_length; step <= (int)max_seq_len; step++) {
476	        FT_LOG_DEBUG("%s::step: %d", __PRETTY_FUNCTION__, step);
477	        const int src_indir_idx = beam_width > 1 ? (step - 1) & 0x1 : 0;
478	        const int tgt_indir_idx = 1 - src_indir_idx;
479	
480	        for (uint ite = 0; ite < iteration_num; ++ite) {
481	            const int id_offset               = ite * local_batch_size * beam_width;
482	            const int d_model_offset          = id_offset * d_model_;
483	            const int vocab_size_units_offset = id_offset * vocab_size_padded_;
484	
485	            if (pipeline_para_.rank_ == 0) {
486	                invokeEmbeddingLookupPosEncodingPadCount(decoder_input_buf_ + d_model_offset,
487	                                                         decoding_weights->pre_decoder_embedding_table,
488	                                                         decoding_weights->position_embedding_type
489	                                                                 == PositionEmbeddingType::relative ?
490	                                                             (T*)nullptr :
491	                                                             decoding_weights->absolute_or_relative_position_embedding,
492	                                                         output_ids_buf_ + id_offset,
493	                                                         nullptr,
494	                                                         local_batch_size * beam_width,
495	                                                         d_model_,
496	                                                         (T)1.0f,
497	                                                         step - 1,
498	                                                         batch_size * beam_width,
499	                                                         0,
500	                                                         stream_);
501	                sync_check_cuda_error();
502	            }
503	
504	            // BART/mBART has a layernorm after word + positional embedding
505	            invokeGeneralT5LayerNorm(decoder_input_buf_ + d_model_offset,
506	                                     decoder_input_buf_ + d_model_offset,
507	                                     decoding_weights->pre_decoder_layernorm.gamma,
508	                                     decoding_weights->pre_decoder_layernorm.beta,
509	                                     layernorm_eps_,
510	                                     local_batch_size * beam_width,
511	                                     d_model_,
512	                                     stream_);
513	            sync_check_cuda_error();
514	
515	            std::vector<Tensor> decoder_input_tensors{
516	                Tensor{MEMORY_GPU,
517	                       data_type,
518	                       {local_batch_size * beam_width, d_model_},
519	                       decoder_input_buf_ + d_model_offset},
520	                Tensor{MEMORY_GPU,
521	                       data_type,
522	                       {local_batch_size * beam_width,
523	                        input_tensors->at("encoder_output").shape[1],
524	                        input_tensors->at("encoder_output").shape[2]},
525	                       encoder_output_ptr_
526	                           + id_offset * input_tensors->at("encoder_output").shape[1]
527	                                 * input_tensors->at("encoder_output").shape[2]},
528	                Tensor{
529	                    MEMORY_GPU, TYPE_INT32, {local_batch_size * beam_width}, encoder_sequence_length_ptr_ + id_offset},
530	                Tensor{MEMORY_GPU, TYPE_BOOL, {local_batch_size * beam_width}, finished_buf_ + id_offset},
531	                Tensor{MEMORY_CPU, TYPE_INT32, {1}, &step},
532	                Tensor{MEMORY_GPU, TYPE_INT32, {local_batch_size * beam_width}, sequence_lengths + id_offset},
533	                Tensor{MEMORY_GPU,
534	                       data_type,
535	                       {1, head_num_, max_seq_len + 1, max_seq_len + 1},
536	                       decoding_weights->position_embedding_type == PositionEmbeddingType::relative ?
537	                           relative_attention_bias_ :
538	                           nullptr},
539	                Tensor{MEMORY_CPU, TYPE_UINT32, {1}, &ite},
540	                Tensor{MEMORY_GPU,
541	                       TYPE_INT32,
542	                       {local_batch_size, beam_width, max_seq_len + 1},
543	                       beam_width > 1 ? cache_indirections_[src_indir_idx] + id_offset * (max_seq_len + 1) : nullptr}};
544	
545	            std::vector<Tensor> decoder_output_tensors{
546	                Tensor{MEMORY_GPU,
547	                       data_type,
548	                       {local_batch_size * beam_width, d_model_},
549	                       decoder_output_buf_ + d_model_offset},
550	                Tensor{MEMORY_GPU, data_type, self_k_cache_shape, key_cache_},
551	                Tensor{MEMORY_GPU, data_type, self_v_cache_shape, value_cache_},
552	                Tensor{MEMORY_GPU, data_type, mem_cache_shape, key_mem_cache_},
553	                Tensor{MEMORY_GPU, data_type, mem_cache_shape, value_mem_cache_}};
554	
555	            if (output_tensors->isExist("cross_attentions")) {
556	                decoder_output_tensors.push_back(Tensor{
557	                    MEMORY_GPU,
558	                    TYPE_FP32,
559	                    output_tensors->at("cross_attentions").shape,
560	                    output_tensors->at("cross_attentions").data,
561	                    {(size_t)id_offset,
562	                     batch_size * beam_width * head_num_ / tensor_para_.world_size_ * max_seq_len * mem_max_seq_len}});
563	            }
564	
565	            decoder_->forward(
566	                &decoder_output_tensors, &decoder_input_tensors, &decoding_weights->decoder_layer_weights);
567	
568	            bool bart_with_bias = decoding_weights->bart_with_bias;
569	            bool mbart          = decoding_weights->mbart;
570	
571	            const cudaDataType_t gemm_data_type = getCudaDataType<T>();
572	
573	            if (pipeline_para_.rank_ == pipeline_para_.world_size_ - 1) {
574	                T* decoder_output_buf_tmp = mbart ? normed_decoder_output_buf_ : decoder_output_buf_;
575	
576	                if (mbart) {
577	                    invokeGeneralT5LayerNorm(decoder_output_buf_tmp + d_model_offset,
578	                                             decoder_output_buf_ + d_model_offset,
579	                                             decoding_weights->post_decoder_layernorm.gamma,
580	                                             decoding_weights->post_decoder_layernorm.beta,
581	                                             layernorm_eps_,
582	                                             local_batch_size * beam_width,
583	                                             d_model_,
584	                                             stream_);
585	                }
586	
587	                sync_check_cuda_error();
588	
589	                DataType logits_data_type = data_type;
590	
591	                // bf16 logits computation fallback to fp32
592	                if (tensor_para_.world_size_ == 1) {
593	                    float alpha = (!bart_with_bias && tie_word_embeddings_) ? 1.0f / sqrt(d_model_) : 1.0f;
594	                    float beta  = 0.0f;
595	#ifdef ENABLE_BF16
596	                    if (std::is_same<T, __nv_bfloat16>::value) {
597	                        logits_data_type = TYPE_FP32;
598	#else
599	                    if (false) {
600	#endif
601	                        cublas_wrapper_->Gemm(CUBLAS_OP_T,
602	                                              CUBLAS_OP_N,
603	                                              vocab_size_padded_,  // n
604	                                              local_batch_size * beam_width,
605	                                              d_model_,  // k
606	                                              &alpha,
607	                                              padded_embedding_kernel_ptr_,
608	                                              gemm_data_type,
609	                                              d_model_,  // k
610	                                              decoder_output_buf_tmp + d_model_offset,
611	                                              gemm_data_type,
612	                                              d_model_,  // k
613	                                              &beta,
614	                                              logits_buf_ + vocab_size_units_offset,
615	                                              CUDA_R_32F,
616	                                              vocab_size_padded_, /* n */
617	                                              CUDA_R_32F,
618	                                              cublasGemmAlgo_t(-1));
619	                    }
620	                    else {
621	                        cublas_wrapper_->Gemm(CUBLAS_OP_T,
622	                                              CUBLAS_OP_N,
623	                                              vocab_size_padded_,  // n
624	                                              local_batch_size * beam_width,
625	                                              d_model_,  // k
626	                                              padded_embedding_kernel_ptr_,
627	                                              d_model_,  // k
628	                                              decoder_output_buf_tmp + d_model_offset,
629	                                              d_model_,  // k
630	                                              logits_buf_ + vocab_size_units_offset,
631	                                              vocab_size_padded_ /* n */,
632	                                              alpha,
633	                                              beta);
634	                    }
635	                }
636	                else {
637	                    const int local_vocab_size = vocab_size_padded_ / tensor_para_.world_size_;
638	                    float     alpha = (!bart_with_bias && tie_word_embeddings_) ? 1.0f / sqrt(d_model_) : 1.0f;
639	                    float     beta  = 0.0f;
640	#ifdef ENABLE_BF16
641	                    if (std::is_same<T, __nv_bfloat16>::value) {
642	                        logits_data_type = TYPE_FP32;
643	#else
644	                    if (false) {
645	#endif
646	                        cublas_wrapper_->Gemm(
647	                            CUBLAS_OP_T,
648	                            CUBLAS_OP_N,
649	                            local_vocab_size,  // n
650	                            local_batch_size * beam_width,
651	                            d_model_,  // k
652	                            &alpha,
653	                            padded_embedding_kernel_ptr_ + tensor_para_.rank_ * local_vocab_size * d_model_,
654	                            gemm_data_type,
655	                            d_model_,  // k
656	                            decoder_output_buf_tmp + d_model_offset,
657	                            gemm_data_type,
658	                            d_model_,  // k
659	                            &beta,
660	                            nccl_logits_buf_ + vocab_size_units_offset
661	                                + tensor_para_.rank_ * local_batch_size * beam_width * local_vocab_size,
662	                            CUDA_R_32F,
663	                            local_vocab_size, /* n */
664	                            CUDA_R_32F,
665	                            cublasGemmAlgo_t(-1));
666	                    }
667	                    else {
668	                        cublas_wrapper_->Gemm(
669	                            CUBLAS_OP_T,
670	                            CUBLAS_OP_N,
671	                            local_vocab_size,  // n
672	                            local_batch_size * beam_width,
673	                            d_model_,  // k
674	                            padded_embedding_kernel_ptr_ + tensor_para_.rank_ * local_vocab_size * d_model_,
675	                            d_model_,  // k
676	                            decoder_output_buf_tmp + d_model_offset,
677	                            d_model_,  // k
678	                            nccl_logits_buf_ + vocab_size_units_offset
679	                                + tensor_para_.rank_ * local_batch_size * beam_width * local_vocab_size,
680	                            local_vocab_size /* n */,
681	                            alpha,
682	                            beta);
683	                    }
684	                    ftNcclAllGather(nccl_logits_buf_ + vocab_size_units_offset,
685	                                    nccl_logits_buf_ + vocab_size_units_offset,
686	                                    local_batch_size * beam_width * local_vocab_size,
687	                                    tensor_para_.rank_,
688	                                    tensor_para_,
689	                                    stream_);
690	                    invokeTransposeAxis01(logits_buf_ + vocab_size_units_offset,
691	                                          nccl_logits_buf_ + vocab_size_units_offset,
692	                                          tensor_para_.world_size_,
693	                                          local_batch_size * beam_width,
694	                                          local_vocab_size,
695	                                          stream_);
696	                }
697	
698	                if (bart_with_bias) {
699	                    invokeGenericActivation<IdentityActivation, DynamicDecodeType, T>(
700	                        logits_buf_ + vocab_size_units_offset,
701	                        padded_post_decoder_embedding_bias_ptr_,
702	                        nullptr,
703	                        nullptr,
704	                        nullptr,
705	                        nullptr,
706	                        local_batch_size * beam_width,
707	                        vocab_size_padded_,
708	                        0,
709	                        nullptr,
710	                        nullptr,
711	                        stream_);
712	                }
713	
714	                int       tmp_local_batch_size       = local_batch_size;
715	                bool      is_initialize_random_table = step == 1;
716	                TensorMap dynamic_decode_input_tensors(
717	                    {{"logits",
718	                      Tensor{MEMORY_GPU, logits_data_type, {batch_size, beam_width, vocab_size_padded_}, logits_buf_}},
719	                     {"step", Tensor{MEMORY_CPU, TYPE_INT32, {1}, &step}},
720	                     {"max_input_length", Tensor{MEMORY_CPU, TYPE_INT32, {1}, &max_input_length}},
721	                     {"ite", Tensor{MEMORY_CPU, TYPE_UINT32, {1}, &ite}},
722	                     {"end_id", Tensor{MEMORY_GPU, TYPE_INT32, {batch_size}, end_ids_buf_}},
723	                     {"local_batch_size", Tensor{MEMORY_CPU, TYPE_INT32, {1}, &tmp_local_batch_size}},
724	                     {"is_initialize_random_table", Tensor{MEMORY_CPU, TYPE_BOOL, {1}, &is_initialize_random_table}}});
725	
726	                if (cache_indirections_[src_indir_idx] != nullptr) {
727	                    dynamic_decode_input_tensors.insert(
728	                        "src_cache_indirection",
729	                        Tensor{MEMORY_GPU,
730	                               TYPE_INT32,
731	                               {local_batch_size, beam_width, (max_seq_len + 1)},
732	                               cache_indirections_[src_indir_idx] + id_offset * (max_seq_len + 1)});
733	                }
734	
735	                for (auto t = input_tensors->begin(); t != input_tensors->end(); ++t) {
736	                    if (!dynamic_decode_input_tensors.isExist(t->first)) {
737	                        dynamic_decode_input_tensors.insert(*t);
738	                    }
739	                }
740	
741	                // common outputs
742	                TensorMap dynamic_decode_output_tensors(
743	                    {{"output_ids",
744	                      Tensor{MEMORY_GPU, TYPE_INT32, {(max_seq_len + 1), batch_size, beam_width}, output_ids_buf_}},
745	                     {"finished", Tensor{MEMORY_GPU, TYPE_BOOL, {batch_size * beam_width}, finished_buf_}},
746	                     {"parent_ids",
747	                      Tensor{MEMORY_GPU, TYPE_INT32, {(max_seq_len + 1), batch_size, beam_width}, parent_ids_buf_}},
748	                     {"sequence_length", Tensor{MEMORY_GPU, TYPE_INT32, {batch_size * beam_width}, sequence_lengths}}});
749	
750	                if (using_beam_hyps) {
751	                    dynamic_decode_output_tensors.insert("beam_hyps", Tensor{MEMORY_GPU, TYPE_VOID, {1}, &beam_hyps_});
752	                }
753	
754	                // cum_log_probs is necessary for beam search, while it is optional for sampling.
755	                if (beam_width > 1 || output_tensors->isExist("cum_log_probs")) {
756	                    dynamic_decode_output_tensors.insert(
757	                        "cum_log_probs", Tensor{MEMORY_GPU, TYPE_FP32, {batch_size * beam_width}, cum_log_probs_});
758	                }
759	
760	                if (output_tensors->getPtr<float>("output_log_probs", nullptr) != nullptr) {
761	                    dynamic_decode_output_tensors.insert(
762	                        "output_log_probs",
763	                        Tensor{
764	                            MEMORY_GPU, TYPE_FP32, {(max_seq_len + 1), batch_size, beam_width}, output_log_probs_buf_});
765	                }
766	
767	                if (cache_indirections_[tgt_indir_idx] != nullptr) {
768	                    dynamic_decode_output_tensors.insert(
769	                        "tgt_cache_indirection",
770	                        Tensor{MEMORY_GPU,
771	                               TYPE_INT32,
772	                               {local_batch_size, beam_width, (max_seq_len + 1)},
773	                               cache_indirections_[tgt_indir_idx] + id_offset * (max_seq_len + 1)});
774	                }
775	
776	                for (auto t = output_tensors->begin(); t != output_tensors->end(); ++t) {
777	                    // Handle exceptions.
778	                    if (t->first == "cum_log_probs" || t->first == "output_log_probs") {
779	                        continue;
780	                    }
781	                    dynamic_decode_output_tensors.insert(*t);
782	                }
783	
784	                dynamic_decode_layer_->forward(&dynamic_decode_output_tensors, &dynamic_decode_input_tensors);
785	            }
786	        }
787	
788	        if (pipeline_para_.world_size_ > 1) {
789	            ftNcclGroupStart();
790	            ftNcclBroadCast(output_ids_buf_ + step * batch_size * beam_width,
791	                            batch_size * beam_width,
792	                            pipeline_para_.world_size_ - 1,
793	                            pipeline_para_,
794	                            stream_);
795	
796	            ftNcclBroadCast(
797	                sequence_lengths, batch_size * beam_width, pipeline_para_.world_size_ - 1, pipeline_para_, stream_);
798	
799	            ftNcclBroadCast(
800	                finished_buf_, batch_size * beam_width, pipeline_para_.world_size_ - 1, pipeline_para_, stream_);
801	
802	            if (beam_width > 1) {
803	                ftNcclBroadCast(cache_indirections_[tgt_indir_idx],
804	                                batch_size * beam_width * (max_seq_len + 1),
805	                                pipeline_para_.world_size_ - 1,
806	                                pipeline_para_,
807	                                stream_);
808	            }
809	            ftNcclGroupEnd();
810	            // throw errors when detected
811	            ftNcclStreamSynchronize(tensor_para_, pipeline_para_, stream_);
812	            sync_check_cuda_error();
813	        }
814	
815	        cudaD2Hcpy(h_finished_buf_, finished_buf_, batch_size * beam_width);
816	        uint sum = 0;
817	        for (uint i = 0; i < batch_size * beam_width; i++) {
818	            sum += (int)h_finished_buf_[i];
819	        }
820	        if (sum == batch_size * beam_width) {
821	            break;
822	        }
823	    }
824	
825	    if (pipeline_para_.rank_ == pipeline_para_.world_size_ - 1) {
826	        if (beam_width > 1) {
827	            if (using_beam_hyps) {
828	                beam_hyps_.sequence_lengths_src = sequence_lengths;
829	                beam_hyps_.parent_ids_src       = parent_ids_buf_;
830	                beam_hyps_.output_ids_src       = output_ids_buf_;
831	                beam_hyps_.log_probs_src        = output_log_probs_buf_;
832	                beam_hyps_.max_seq_len          = max_seq_len;
833	                beam_hyps_.length_penalty =
834	                    input_tensors->isExist("len_penalty") ? input_tensors->at("len_penalty").getVal<float>() : 0.0f;
835	
836	                invokeInsertUnfinishedPath(beam_hyps_, finished_buf_, cum_log_probs_, batch_size, beam_width, stream_);
837	                sync_check_cuda_error();
838	
839	                invokeFinalize(output_tensors->at("output_ids").getPtr<int>(),
840	                               output_tensors->at("sequence_length").getPtr<int>(),
841	                               output_tensors->getPtr<float>("cum_log_probs", nullptr),
842	                               output_tensors->getPtr<float>("output_log_probs", nullptr),
843	                               beam_hyps_.output_ids_tgt,
844	                               beam_hyps_.sequence_lengths_tgt,
845	                               beam_hyps_.normed_scores,
846	                               beam_hyps_.cum_log_probs,
847	                               beam_hyps_.log_probs,
848	                               beam_hyps_.num_beams,
849	                               beam_width,
850	                               max_seq_len,
851	                               batch_size,
852	                               stream_);
853	                sync_check_cuda_error();
854	            }
855	            else {
856	                // For beam search, do gather_tree
857	                invokeGatherTree(output_ids_transpose_buf_,
858	                                 output_tensors->at("sequence_length").getPtr<int>(),
859	                                 max_seq_len,
860	                                 batch_size,
861	                                 beam_width,
862	                                 output_ids_buf_ + batch_size * beam_width,
863	                                 parent_ids_buf_ + batch_size * beam_width,
864	                                 end_ids_buf_,
865	                                 stream_);
866	
867	                // transpose and take output_parent_ids as inter buffer
868	                invokeTransposeAxis01(output_tensors->at("output_ids").getPtr<int>(),
869	                                      output_ids_transpose_buf_,
870	                                      max_seq_len,
871	                                      batch_size * beam_width,
872	                                      1,
873	                                      stream_);
874	            }
875	        }
876	        else {
877	            // For sampling, only transpose the results to output_tensor
878	            invokeTransposeAxis01(output_tensors->at("output_ids").getPtr<int>(),
879	                                  output_ids_buf_ + batch_size * beam_width,
880	                                  max_seq_len,
881	                                  batch_size * beam_width,
882	                                  1,
883	                                  stream_);
884	        }
885	        if (output_tensors->isExist("output_log_probs")) {
886	            invokeTransposeAxis01(output_tensors->at("output_log_probs").getPtr<float>(),
887	                                  output_log_probs_buf_,
888	                                  max_seq_len,
889	                                  batch_size * beam_width,
890	                                  1,
891	                                  stream_);
892	        }
893	
894	        // Return the cumulative log probability and log probability if requested.
895	        if (!using_beam_hyps) {
896	            if (output_tensors->isExist("output_log_probs")) {
897	                invokeTransposeAxis01(output_tensors->at("output_log_probs").getPtr<float>(),
898	                                      output_log_probs_buf_,
899	                                      max_seq_len,
900	                                      batch_size * beam_width,
901	                                      1,
902	                                      stream_);
903	            }
904	            if (output_tensors->isExist("cum_log_probs")) {
905	                Tensor cum_log_probs = output_tensors->at("cum_log_probs");
906	                FT_CHECK_WITH_INFO(cum_log_probs.size() == batch_size * beam_width,
907	                                   "The shape of cum_log_probs does not match with batch_size x beam_width.");
908	                cudaD2Dcpy(cum_log_probs.getPtr<float>(), cum_log_probs_, batch_size * beam_width);
909	            }
910	        }
911	    }
912	
913	    if (pipeline_para_.world_size_ > 1) {
914	        ftNcclGroupStart();
915	        if (pipeline_para_.rank_ == pipeline_para_.world_size_ - 1) {
916	            ftNcclSend(output_tensors->at("output_ids").getPtr<int>(),
917	                       batch_size * beam_width * max_seq_len,
918	                       0,
919	                       pipeline_para_,
920	                       stream_);
921	
922	            ftNcclSend(output_tensors->at("sequence_length").getPtr<int>(),
923	                       batch_size * beam_width,
924	                       0,
925	                       pipeline_para_,
926	                       stream_);
927	
928	            if (output_tensors->isExist("cum_log_probs") && output_tensors->at("cum_log_probs").data != nullptr) {
929	                ftNcclSend(output_tensors->at("cum_log_probs").getPtr<float>(),
930	                           batch_size * beam_width,
931	                           0,
932	                           pipeline_para_,
933	                           stream_);
934	            }
935	
936	            if (output_tensors->isExist("output_log_probs") && output_tensors->at("output_log_probs").data != nullptr) {
937	                ftNcclSend(output_tensors->at("output_log_probs").getPtr<float>(),
938	                           batch_size * beam_width * max_seq_len,
939	                           0,
940	                           pipeline_para_,
941	                           stream_);
942	            }
943	        }
944	        else if (pipeline_para_.rank_ == 0) {
945	            ftNcclRecv(output_tensors->at("output_ids").getPtr<int>(),
946	                       batch_size * beam_width * max_seq_len,
947	                       pipeline_para_.world_size_ - 1,
948	                       pipeline_para_,
949	                       stream_);
950	
951	            ftNcclRecv(output_tensors->at("sequence_length").getPtr<int>(),
952	                       batch_size * beam_width,
953	                       pipeline_para_.world_size_ - 1,
954	                       pipeline_para_,
955	                       stream_);
956	
957	            if (output_tensors->isExist("cum_log_probs") && output_tensors->at("cum_log_probs").data != nullptr) {
958	                ftNcclRecv(output_tensors->at("cum_log_probs").getPtr<float>(),
959	                           batch_size * beam_width,
960	                           pipeline_para_.world_size_ - 1,
961	                           pipeline_para_,
962	                           stream_);
963	            }
964	
965	            if (output_tensors->isExist("output_log_probs") && output_tensors->at("output_log_probs").data != nullptr) {
966	                ftNcclRecv(output_tensors->at("output_log_probs").getPtr<float>(),
967	                           batch_size * beam_width * max_seq_len,
968	                           pipeline_para_.world_size_ - 1,
969	                           pipeline_para_,
970	                           stream_);
971	            }
972	        }
973	        ftNcclGroupEnd();
974	    }
975	
976	    // throw errors when detected
977	    ftNcclStreamSynchronize(tensor_para_, pipeline_para_, stream_);
978	
979	    if (is_free_buffer_after_forward_) {
980	        freeBuffer();
981	    }
982	}
983	
984	template class BartDecoding<float>;
985	template class BartDecoding<half>;
986	#ifdef ENABLE_BF16
987	template class BartDecoding<__nv_bfloat16>;
988	#endif
989	
990	}  // namespace fastertransformer
