25	template<typename T>
26	void T5Decoding<T>::initialize()
27	{
28	    decoder_ = new T5Decoder<T>(0,  // max_batch_size_ * beam_width_,
29	                                head_num_,
30	                                size_per_head_,
31	                                inter_size_,
