60	template<typename T>
61	void T5Decoding<T>::allocateBuffer()
62	{
63	    FT_CHECK(false);
64	}
65	
66	template<typename T>
67	void T5Decoding<T>::allocateBuffer(
68	    size_t batch_size, size_t beam_width, size_t max_seq_len, size_t max_mem_seq_len, size_t encoder_d_model)
69	{
70	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
71	    // Note: To put the start_ids, we use max_seq_len + 1 for ouptut_ids_buf_
72	    // And to consistent to the output_ids_buf_, some related buffers are also
73	    // use max_seq_len + 1, but not max_seq_len.
74	    // This only affects the buffer size, not affect the performance.
75	
76	    const size_t batchxbeam      = batch_size * beam_width;
77	    const size_t self_cache_size = (num_layer_ / pipeline_para_.world_size_) * batchxbeam * (max_seq_len + 1)
78	                                   * (hidden_units_ / tensor_para_.world_size_);
79	    const size_t mem_cache_size = (num_layer_ / pipeline_para_.world_size_) * batchxbeam * max_mem_seq_len
80	                                  * (hidden_units_ / tensor_para_.world_size_);
81	
82	    if (vocab_size_ != vocab_size_padded_) {
83	        padded_embedding_kernel_ =
84	            (T*)(allocator_->reMalloc(padded_embedding_kernel_, sizeof(T) * d_model_ * vocab_size_padded_, true));
85	        padded_embedding_kernel_ptr_ = padded_embedding_kernel_;
86	
87	        padded_post_decoder_embedding_bias_ =
88	            (T*)(allocator_->reMalloc(padded_post_decoder_embedding_bias_, sizeof(T) * vocab_size_padded_, true));
89	        padded_post_decoder_embedding_bias_ptr_ = padded_post_decoder_embedding_bias_;
90	    }
91	    relative_attention_bias_ = (T*)(allocator_->reMalloc(
92	        relative_attention_bias_, sizeof(T) * head_num_ * (max_seq_len + 1) * (max_seq_len + 1), false));
93	
94	    decoder_input_buf_  = (T*)(allocator_->reMalloc(decoder_input_buf_, sizeof(T) * batchxbeam * d_model_, false));
95	    decoder_output_buf_ = (T*)(allocator_->reMalloc(decoder_output_buf_, sizeof(T) * batchxbeam * d_model_, false));
96	    normed_decoder_output_buf_ =
97	        (T*)(allocator_->reMalloc(normed_decoder_output_buf_, sizeof(T) * batchxbeam * d_model_, false));
98	    logits_buf_      = (DynamicDecodeType*)(allocator_->reMalloc(
99	        logits_buf_, sizeof(DynamicDecodeType) * batchxbeam * vocab_size_padded_, false));
100	    nccl_logits_buf_ = (DynamicDecodeType*)(allocator_->reMalloc(
101	        nccl_logits_buf_, sizeof(DynamicDecodeType) * batchxbeam * vocab_size_padded_, false));
102	    cum_log_probs_   = (float*)(allocator_->reMalloc(cum_log_probs_, sizeof(float) * batchxbeam, false));
103	    finished_buf_    = (bool*)(allocator_->reMalloc(finished_buf_, sizeof(bool) * batchxbeam, false));
104	    h_finished_buf_  = (bool*)realloc(h_finished_buf_, sizeof(bool) * batchxbeam);
105	
106	    key_cache_ = (T*)(allocator_->reMalloc(key_cache_, sizeof(T) * (2 * self_cache_size + 2 * mem_cache_size), false));
107	    value_cache_     = key_cache_ + self_cache_size;
108	    key_mem_cache_   = value_cache_ + self_cache_size;
109	    value_mem_cache_ = key_mem_cache_ + mem_cache_size;
110	    if (beam_width > 1) {
111	        cache_indirections_[0] = (int*)(allocator_->reMalloc(
112	            cache_indirections_[0], sizeof(int) * batchxbeam * (max_seq_len + 1) * 2, true));
113	        cache_indirections_[1] = cache_indirections_[0] + batchxbeam * (max_seq_len + 1);
114	    }
115	    tiled_encoder_output_ = (T*)(allocator_->reMalloc(
116	        tiled_encoder_output_, sizeof(T) * batchxbeam * max_mem_seq_len * encoder_d_model, false));
117	    tiled_encoder_sequence_length_ =
118	        (int*)(allocator_->reMalloc(tiled_encoder_sequence_length_, sizeof(int) * batchxbeam, false));
119	
120	    start_ids_buf_ = (int*)(allocator_->reMalloc(start_ids_buf_, sizeof(int) * batch_size, false));
121	    end_ids_buf_   = (int*)(allocator_->reMalloc(end_ids_buf_, sizeof(int) * batch_size, false));
122	
123	    output_ids_buf_ =
124	        (int*)(allocator_->reMalloc(output_ids_buf_, sizeof(int) * batchxbeam * (max_seq_len + 1), false));
125	    parent_ids_buf_ =
126	        (int*)(allocator_->reMalloc(parent_ids_buf_, sizeof(int) * batchxbeam * (max_seq_len + 1), false));
127	    output_ids_transpose_buf_ =
128	        (int*)(allocator_->reMalloc(output_ids_transpose_buf_, sizeof(int) * batchxbeam * (max_seq_len + 1), false));
129	    output_log_probs_buf_ =
130	        (float*)(allocator_->reMalloc(output_log_probs_buf_, sizeof(float) * batchxbeam * (max_seq_len + 1), false));
131	
132	    if (using_beam_hyps) {
133	        // Let beam_hyps_ can record at most 2*beam_width because we
134	        // may find beam_width finished candidates during generation,
135	        // and may compare them with unfinifhsed another beam_width candidates
136	        // during finalization.
137	        beam_hyps_.output_ids_tgt = (int*)allocator_->reMalloc(
138	            beam_hyps_.output_ids_tgt, sizeof(int) * batch_size * beam_width * 2 * (max_seq_len + 1), true);
139	        beam_hyps_.sequence_lengths_tgt = (int*)allocator_->reMalloc(
140	            beam_hyps_.sequence_lengths_tgt, sizeof(int) * batch_size * beam_width * 2, true);
141	        beam_hyps_.cum_log_probs =
142	            (float*)allocator_->reMalloc(beam_hyps_.cum_log_probs, sizeof(float) * batch_size * beam_width * 2, true);
143	        beam_hyps_.normed_scores =
144	            (float*)allocator_->reMalloc(beam_hyps_.normed_scores, sizeof(float) * batch_size * beam_width * 2, true);
145	        beam_hyps_.log_probs = (float*)allocator_->reMalloc(
146	            beam_hyps_.log_probs, sizeof(float) * batch_size * beam_width * 2 * (max_seq_len + 1), true);
147	        beam_hyps_.min_normed_scores =
148	            (float*)allocator_->reMalloc(beam_hyps_.min_normed_scores, sizeof(float) * batch_size, true);
149	        beam_hyps_.num_beams = (int*)allocator_->reMalloc(beam_hyps_.num_beams, sizeof(int) * batch_size, true);
150	        beam_hyps_.is_done   = (bool*)allocator_->reMalloc(beam_hyps_.is_done, sizeof(bool) * batch_size, true);
151	    }
152	    is_allocate_buffer_ = true;
153	}
154	
155	template<typename T>
156	void T5Decoding<T>::freeBuffer()
157	{
158	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
159	    if (is_allocate_buffer_) {
160	        if (vocab_size_ != vocab_size_padded_) {
161	            padded_embedding_kernel_ptr_ = nullptr;
162	            allocator_->free((void**)(&padded_embedding_kernel_));
163	
164	            padded_post_decoder_embedding_bias_ptr_ = nullptr;
165	            allocator_->free((void**)(&padded_post_decoder_embedding_bias_));
166	        }
167	
168	        allocator_->free((void**)(&relative_attention_bias_));
169	
170	        allocator_->free((void**)(&decoder_input_buf_));
171	        allocator_->free((void**)(&decoder_output_buf_));
172	        allocator_->free((void**)(&normed_decoder_output_buf_));
173	        allocator_->free((void**)(&logits_buf_));
174	        allocator_->free((void**)(&nccl_logits_buf_));
175	        allocator_->free((void**)(&cum_log_probs_));
176	        allocator_->free((void**)(&finished_buf_));
177	        free(h_finished_buf_);
178	
179	        allocator_->free((void**)(&key_cache_));
180	        if (cache_indirections_[0] != nullptr) {
181	            allocator_->free((void**)(&cache_indirections_)[0]);
182	        }
183	
184	        allocator_->free((void**)(&tiled_encoder_output_));
185	        allocator_->free((void**)(&tiled_encoder_sequence_length_));
186	
187	        allocator_->free((void**)(&start_ids_buf_));
188	        allocator_->free((void**)(&end_ids_buf_));
189	
190	        allocator_->free((void**)(&output_ids_buf_));
191	        allocator_->free((void**)(&parent_ids_buf_));
192	        allocator_->free((void**)(&output_ids_transpose_buf_));
193	        allocator_->free((void**)(&output_log_probs_buf_));
194	
195	        if (using_beam_hyps) {
196	            allocator_->free((void**)(&beam_hyps_.output_ids_tgt));
197	            allocator_->free((void**)(&beam_hyps_.sequence_lengths_tgt));
198	            allocator_->free((void**)(&beam_hyps_.cum_log_probs));
199	            allocator_->free((void**)(&beam_hyps_.normed_scores));
200	            allocator_->free((void**)(&beam_hyps_.log_probs));
201	            allocator_->free((void**)(&beam_hyps_.min_normed_scores));
202	            allocator_->free((void**)(&beam_hyps_.num_beams));
203	            allocator_->free((void**)(&beam_hyps_.is_done));
204	        }
205	        is_allocate_buffer_ = false;
206	    }
207	}
