354	template<typename T>
355	void T5Decoding<T>::forward(std::vector<Tensor>*       output_tensors,
356	                            const std::vector<Tensor>* input_tensors,
357	                            const T5DecodingWeight<T>* decoding_weights)
358	{
359	    // input_tensors:
360	    //      encoder_output [batch_size, mem_max_seq_len, memory_hidden_dimension]
361	    //      encoder_sequence_length [batch_size]
362	
363	    // output_tensors:
364	    //      output_ids [batch_size, beam, max_seq_len]
365	    //      sequence_length [batch_size, beam], record the number of generated token, except the start token
366	
367	    // Step is from 1 ~ max_seq_len,
368	    // When step = k,  we put output ids and caches at step k, and the sequence_length would be k - 1 before
369	    // complete this step.
370	
371	    std::unordered_map<std::string, Tensor> input_tensors_map{{"encoder_output", input_tensors->at(0)},
372	                                                              {"encoder_sequence_length", input_tensors->at(1)}};
373	
374	    std::unordered_map<std::string, Tensor> output_tensors_map{{"output_ids", output_tensors->at(0)},
375	                                                               {"sequence_length", output_tensors->at(1)}};
376	    forward(&output_tensors_map, &input_tensors_map, decoding_weights);
377	}
