390	template<typename T>
391	void T5Decoding<T>::setOutputTensors(TensorMap* output_tensors, TensorMap const* input_tensors)
392	{
393	    if (pipeline_para_.rank_ != pipeline_para_.world_size_ - 1) {
394	        return;
395	    }
396	
397	    auto const batch_size       = output_tensors->at("output_ids").shape[0];
398	    auto const beam_width       = output_tensors->at("output_ids").shape[1];
399	    auto const sequence_lengths = output_tensors->at("sequence_length").getPtr<int>();
400	    auto const max_seq_len      = output_tensors->at("output_ids").shape[2];
401	
402	    if (beam_width > 1) {
403	        if (using_beam_hyps) {
404	            beam_hyps_.sequence_lengths_src = sequence_lengths;
405	            beam_hyps_.parent_ids_src       = parent_ids_buf_;
406	            beam_hyps_.output_ids_src       = output_ids_buf_;
407	            beam_hyps_.log_probs_src        = output_log_probs_buf_;
408	            beam_hyps_.max_seq_len          = max_seq_len;
409	            beam_hyps_.length_penalty =
410	                input_tensors->isExist("len_penalty") ? input_tensors->at("len_penalty").getVal<float>() : 0.0f;
411	
412	            invokeInsertUnfinishedPath(beam_hyps_, finished_buf_, cum_log_probs_, batch_size, beam_width, stream_);
413	            sync_check_cuda_error();
414	
415	            invokeFinalize(output_tensors->getPtr<int>("output_ids"),
416	                           output_tensors->getPtr<int>("sequence_length"),
417	                           output_tensors->getPtr<float>("cum_log_probs", nullptr),
418	                           output_tensors->getPtr<float>("output_log_probs", nullptr),
419	                           beam_hyps_.output_ids_tgt,
420	                           beam_hyps_.sequence_lengths_tgt,
421	                           beam_hyps_.normed_scores,
422	                           beam_hyps_.cum_log_probs,
423	                           beam_hyps_.log_probs,
424	                           beam_hyps_.num_beams,
425	                           beam_width,
426	                           max_seq_len,
427	                           batch_size,
428	                           stream_);
429	            sync_check_cuda_error();
430	        }
431	        else {
432	            // For beam search, do gather_tree
433	            invokeGatherTree(output_ids_transpose_buf_,
434	                             output_tensors->at("sequence_length").getPtr<int>(),
435	                             max_seq_len,
436	                             batch_size,
437	                             beam_width,
438	                             output_ids_buf_ + batch_size * beam_width,
439	                             parent_ids_buf_ + batch_size * beam_width,
440	                             end_ids_buf_,
441	                             stream_);
442	
443	            // transpose and take output_parent_ids as inter buffer
444	            invokeTransposeAxis01(output_tensors->at("output_ids").getPtr<int>(),
445	                                  output_ids_transpose_buf_,
446	                                  max_seq_len,
447	                                  batch_size * beam_width,
448	                                  1,
449	                                  stream_);
450	        }
451	    }
452	    else {
453	        // For sampling, only transpose the results to output_tensor
454	        invokeTransposeAxis01(output_tensors->at("output_ids").getPtr<int>(),
455	                              output_ids_buf_ + batch_size * beam_width,
456	                              max_seq_len,
457	                              batch_size * beam_width,
458	                              1,
459	                              stream_);
460	    }
461	
462	    // Return the cumulative log probability and log probability if requested.
463	    if (beam_width == 1 || !using_beam_hyps) {
464	        if (output_tensors->isExist("output_log_probs")) {
465	            invokeTransposeAxis01(output_tensors->at("output_log_probs").getPtr<float>(),
466	                                  output_log_probs_buf_,
467	                                  max_seq_len,
468	                                  batch_size * beam_width,
469	                                  1,
470	                                  stream_);
471	        }
472	        if (output_tensors->isExist("cum_log_probs")) {
473	            Tensor cum_log_probs = output_tensors->at("cum_log_probs");
474	            FT_CHECK_WITH_INFO(cum_log_probs.size() == batch_size * beam_width,
475	                               "The shape of cum_log_probs does not match with batch_size x beam_width.");
476	            cudaD2Dcpy(cum_log_probs.getPtr<float>(), cum_log_probs_, batch_size * beam_width);
477	        }
478	    }
479	
480	    if (output_tensors->isExist("is_finished")) {
481	        cudaD2Dcpy(
482	            output_tensors->at("is_finished").getPtr<bool>(), finished_buf_, output_tensors->at("is_finished").size());
483	    }
484	}
