486	template<typename T>
487	void T5Decoding<T>::sendTensorsToFirstPipelineNode(TensorMap* output_tensors, TensorMap const* input_tensors)
488	{
489	    if (pipeline_para_.world_size_ == 1) {
490	        // throw errors when detected
491	        ftNcclStreamSynchronize(tensor_para_, pipeline_para_, stream_);
492	        return;
493	    }
494	
495	    auto const batch_size  = output_tensors->at("output_ids").shape[0];
496	    auto const beam_width  = output_tensors->at("output_ids").shape[1];
497	    auto const max_seq_len = output_tensors->at("output_ids").shape[2];
498	
499	    ftNcclGroupStart();
500	    if (pipeline_para_.rank_ == pipeline_para_.world_size_ - 1) {
501	        ftNcclSend(output_tensors->at("output_ids").getPtr<int>(),
502	                   batch_size * beam_width * max_seq_len,
503	                   0,
504	                   pipeline_para_,
505	                   stream_);
506	
507	        ftNcclSend(
508	            output_tensors->at("sequence_length").getPtr<int>(), batch_size * beam_width, 0, pipeline_para_, stream_);
509	
510	        if (output_tensors->isExist("cum_log_probs") && output_tensors->at("cum_log_probs").data != nullptr) {
511	            ftNcclSend(output_tensors->at("cum_log_probs").getPtr<float>(),
512	                       batch_size * beam_width,
513	                       0,
514	                       pipeline_para_,
515	                       stream_);
516	        }
517	
518	        if (output_tensors->isExist("output_log_probs") && output_tensors->at("output_log_probs").data != nullptr) {
519	            ftNcclSend(output_tensors->at("output_log_probs").getPtr<float>(),
520	                       batch_size * beam_width * max_seq_len,
521	                       0,
522	                       pipeline_para_,
523	                       stream_);
524	        }
525	    }
526	    else if (pipeline_para_.rank_ == 0) {
527	        ftNcclRecv(output_tensors->at("output_ids").getPtr<int>(),
528	                   batch_size * beam_width * max_seq_len,
529	                   pipeline_para_.world_size_ - 1,
530	                   pipeline_para_,
531	                   stream_);
532	
533	        ftNcclRecv(output_tensors->at("sequence_length").getPtr<int>(),
534	                   batch_size * beam_width,
535	                   pipeline_para_.world_size_ - 1,
536	                   pipeline_para_,
537	                   stream_);
538	
539	        if (output_tensors->isExist("cum_log_probs") && output_tensors->at("cum_log_probs").data != nullptr) {
540	            ftNcclRecv(output_tensors->at("cum_log_probs").getPtr<float>(),
541	                       batch_size * beam_width,
542	                       pipeline_para_.world_size_ - 1,
543	                       pipeline_para_,
544	                       stream_);
545	        }
546	
547	        if (output_tensors->isExist("output_log_probs") && output_tensors->at("output_log_probs").data != nullptr) {
548	            ftNcclRecv(output_tensors->at("output_log_probs").getPtr<float>(),
549	                       batch_size * beam_width * max_seq_len,
550	                       pipeline_para_.world_size_ - 1,
551	                       pipeline_para_,
552	                       stream_);
553	        }
554	    }
555	    ftNcclGroupEnd();
556	
557	    // throw errors when detected
558	    ftNcclStreamSynchronize(tensor_para_, pipeline_para_, stream_);
559	}
