561	template<typename T>
562	void T5Decoding<T>::forward(TensorMap*                 output_tensors,
563	                            TensorMap*                 input_tensors,
564	                            const T5DecodingWeight<T>* decoding_weights)
565	{
566	    // input_tensors:
567	    //      encoder_output [batch_size, mem_max_seq_len, memory_hidden_dimension]
568	    //      encoder_sequence_length [batch_size]
569	    //      stop_words_list [batch_size, 2, stop_words_length], optional
570	    //      bad_words_list [batch_size, 2, stop_words_length], optional
571	    //      start_id [batch_size] on cpu, optional
572	    //      end_id [batch_size] on cpu, optional
573	    //      runtime_top_k [1] or [batch_size] on cpu, optional, uint.
574	    //      runtime_top_p [1] or [batch_size] on cpu, optional, float.
575	    //      beam_search_diversity_rate [1] or [batch_size] on cpu, optional, float.
576	    //      temperature [1] or [batch_size] on cpu, optional, float.
577	    //      len_penalty [1] or [batch_size] on cpu, optional, float.
578	    //      repetition_penalty [1] or [batch_size] on cpu, optional, float.
579	    //      presence_penalty [1] or [batch_size] on cpu, optional, float.
580	    //          Only one of repetition and presence penalties is allowed.
581	    //      min_length [1] or [batch_size] on cpu, optional, int
582	    //      random_seed [1] or [batch_size] on cpu, optional, unsigned long long int.
583	    //      top_p_decay [batch_size] on gpu, float, optional
584	    //      top_p_min [batch_size] on gpu, float, optional
585	    //      top_p_reset_ids [batch_size] on gpu, uint32, optional
586	    //      ia3_tasks [batch_size], optional
587	
588	    // output_tensors:
589	    //      output_ids [batch_size, beam, max_seq_len]
590	    //      sequence_length [batch_size, beam], record the number of generated token, except the start token
591	    //      output_log_probs [batch_size, beam, max_seq_len], optional, must be float*.
592	    //      cum_log_probs [batch_size, beam], optional, must be float*.
593	    //      cross_attentions [num_layer / pipeline_para_size, batch_size, beam,
594	    //         head_num / tensor_para_size, max_seq_len, mem_max_seq_len], optional, must be float*.
595	
596	    // Step is from 1 ~ max_seq_len,
597	    // When step = k,  we put output ids and caches at step k, and the sequence_length would be k - 1 before
598	    // complete this step.
599	
600	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
601	    FT_CHECK(input_tensors->size() >= 2);
602	    FT_CHECK(output_tensors->size() >= 2);
603	    FT_CHECK(input_tensors->at("encoder_output").shape.size() == 3);
604	    const size_t batch_size      = output_tensors->at("output_ids").shape[0];
605	    const size_t beam_width      = output_tensors->at("output_ids").shape[1];
606	    const size_t max_seq_len     = output_tensors->at("output_ids").shape[2];
607	    const size_t mem_max_seq_len = input_tensors->at("encoder_output").shape[1];
608	    const bool   has_ia3_tasks   = input_tensors->isExist("ia3_tasks");
609	    allocateBuffer(batch_size, beam_width, max_seq_len, mem_max_seq_len, input_tensors->at("encoder_output").shape[2]);
610	
611	    {
612	        TensorMap input_map(*input_tensors);
613	        dynamic_decode_layer_->setup(batch_size, beam_width, &input_map);
614	        handleOptArg(&input_map, "start_id", start_ids_buf_, start_id_, batch_size);
615	        handleOptArg(&input_map, "end_id", end_ids_buf_, end_id_, batch_size);
616	    }
617	
618	    FT_CHECK_WITH_INFO(input_tensors->at("encoder_output").shape[2] == d_model_,
619	                       fmtstr("expect input_tensors->at(\"encoder_output\").shape[2] == d_model_, "
620	                              "but get input_tensors->at(\"encoder_output\").shape[2] = %d, d_model_ = %d",
621	                              input_tensors->at("encoder_output").shape[2],
622	                              d_model_));
623	    if (has_ia3_tasks) {
624	        FT_CHECK_WITH_INFO(batch_size == input_tensors->at("ia3_tasks").shape[0],
625	                           fmtstr("\"ia3_tasks\" tensor has shape [%d], expected [%d]\n",
626	                                  input_tensors->at("ia3_tasks").shape[0],
627	                                  batch_size));
628	    }
629	
630	    const int      max_input_length = 1;
631	    const DataType data_type        = getTensorType<T>();
632	    int*           sequence_lengths = output_tensors->at("sequence_length").getPtr<int>();
633	
634	    cudaMemsetAsync(
635	        output_tensors->at("output_ids").getPtr<int>(), 0, output_tensors->at("output_ids").sizeBytes(), stream_);
636	    cudaMemsetAsync(output_ids_buf_, 0, sizeof(int) * batch_size * beam_width * (max_seq_len + 1), stream_);
637	    cudaMemsetAsync(parent_ids_buf_, 0, sizeof(int) * batch_size * beam_width * (max_seq_len + 1), stream_);
638	    if (beam_width > 1) {
639	        cudaMemsetAsync(
640	            cache_indirections_[0], 0, 2 * sizeof(int) * batch_size * beam_width * (max_seq_len + 1), stream_);
641	    }
642	
643	    if (beam_width > 1) {
644	        invokeTileEncoderResults(tiled_encoder_output_,
645	                                 tiled_encoder_sequence_length_,
646	                                 input_tensors->at("encoder_output").getPtr<T>(),
647	                                 input_tensors->at("encoder_sequence_length").getPtr<const int>(),
648	                                 batch_size,
649	                                 beam_width,
650	                                 mem_max_seq_len,
651	                                 d_model_,
652	                                 stream_);
653	        sync_check_cuda_error();
654	        encoder_output_ptr_          = tiled_encoder_output_;
655	        encoder_sequence_length_ptr_ = tiled_encoder_sequence_length_;
656	    }
657	    else {
658	        encoder_output_ptr_          = input_tensors->at("encoder_output").getPtr<const T>();
659	        encoder_sequence_length_ptr_ = input_tensors->at("encoder_sequence_length").getPtr<const int>();
660	    }
661	
662	    invokeDecodingInitialize(finished_buf_,
663	                             sequence_lengths,
664	                             output_ids_buf_,
665	                             cum_log_probs_,
666	                             start_ids_buf_,
667	                             batch_size,
668	                             beam_width,
669	                             max_input_length - 1,
670	                             stream_);
671	    sync_check_cuda_error();
672	
673	    invokeBuildRelativeAttentionBias(relative_attention_bias_,
674	                                     decoding_weights->absolute_or_relative_position_embedding,
675	                                     head_num_,
676	                                     (max_seq_len + 1),
677	                                     num_bucket_,
678	                                     false,
679	                                     max_distance_,
680	                                     decoding_weights->position_embedding_type,
681	                                     stream_);
682	    sync_check_cuda_error();
683	
684	    if (vocab_size_ == vocab_size_padded_) {
685	        padded_embedding_kernel_ptr_            = decoding_weights->post_decoder_embedding.kernel;
686	        padded_post_decoder_embedding_bias_ptr_ = decoding_weights->post_decoder_embedding.bias;
687	    }
688	    else {
689	        invokePaddingEmbeddingKernel(padded_embedding_kernel_,
690	                                     decoding_weights->post_decoder_embedding.kernel,
691	                                     d_model_,
692	                                     vocab_size_,
693	                                     vocab_size_padded_,
694	                                     stream_);
695	        sync_check_cuda_error();
696	        if (decoding_weights->post_decoder_embedding.bias != nullptr) {
697	            cudaAutoCpy(padded_post_decoder_embedding_bias_,
698	                        decoding_weights->post_decoder_embedding.bias,
699	                        vocab_size_,
700	                        stream_);
701	        }
702	    }
703	
704	    const std::vector<size_t> self_k_cache_shape = {num_layer_ / pipeline_para_.world_size_,
705	                                                    batch_size * beam_width,
706	                                                    head_num_ / tensor_para_.world_size_,
707	                                                    size_per_head_ / (16 / sizeof(T)),
708	                                                    max_seq_len + 1,
709	                                                    16 / sizeof(T)};
710	    const std::vector<size_t> self_v_cache_shape = {num_layer_ / pipeline_para_.world_size_,
711	                                                    batch_size * beam_width,
712	                                                    head_num_ / tensor_para_.world_size_,
713	                                                    (size_t)(max_seq_len + 1),
714	                                                    size_per_head_};
715	    const std::vector<size_t> mem_cache_shape    = {num_layer_ / pipeline_para_.world_size_,
716	                                                    batch_size * beam_width,
717	                                                    mem_max_seq_len,
718	                                                    head_num_ / tensor_para_.world_size_ * size_per_head_};
719	
720	    const size_t local_batch_size = getLocalBatchSize(batch_size, 1, pipeline_para_.world_size_);
721	    FT_CHECK(batch_size % local_batch_size == 0);
722	    const size_t iteration_num = batch_size / local_batch_size;
723	    for (int step = max_input_length; step <= (int)max_seq_len; step++) {
724	        FT_LOG_DEBUG("%s::step: %d", __PRETTY_FUNCTION__, step);
725	        const int src_indir_idx = beam_width > 1 ? (step - 1) & 0x1 : 0;
726	        const int tgt_indir_idx = 1 - src_indir_idx;
727	
728	        for (uint ite = 0; ite < iteration_num; ++ite) {
729	            const int id_offset               = ite * local_batch_size * beam_width;
730	            const int d_model_offset          = id_offset * d_model_;
731	            const int vocab_size_units_offset = id_offset * vocab_size_padded_;
732	
733	            if (pipeline_para_.rank_ == 0) {
734	                invokeEmbeddingLookupPosEncodingPadCount(decoder_input_buf_ + d_model_offset,
735	                                                         decoding_weights->pre_decoder_embedding_table,
736	                                                         decoding_weights->position_embedding_type
737	                                                                 == PositionEmbeddingType::relative ?
738	                                                             (T*)nullptr :
739	                                                             decoding_weights->absolute_or_relative_position_embedding,
740	                                                         output_ids_buf_ + id_offset,
741	                                                         nullptr,
742	                                                         local_batch_size * beam_width,
743	                                                         d_model_,
744	                                                         (T)1.0f,
745	                                                         step - 1,
746	                                                         batch_size * beam_width,
747	                                                         0,
748	                                                         stream_);
749	                sync_check_cuda_error();
750	            }
751	
752	            std::vector<Tensor> decoder_input_tensors{
753	                Tensor{MEMORY_GPU,
754	                       data_type,
755	                       {local_batch_size * beam_width, d_model_},
756	                       decoder_input_buf_ + d_model_offset},
757	                Tensor{MEMORY_GPU,
758	                       data_type,
759	                       {local_batch_size * beam_width,
760	                        input_tensors->at("encoder_output").shape[1],
761	                        input_tensors->at("encoder_output").shape[2]},
762	                       encoder_output_ptr_
763	                           + id_offset * input_tensors->at("encoder_output").shape[1]
764	                                 * input_tensors->at("encoder_output").shape[2]},
765	                Tensor{
766	                    MEMORY_GPU, TYPE_INT32, {local_batch_size * beam_width}, encoder_sequence_length_ptr_ + id_offset},
767	                Tensor{MEMORY_GPU, TYPE_BOOL, {local_batch_size * beam_width}, finished_buf_ + id_offset},
768	                Tensor{MEMORY_CPU, TYPE_INT32, {1}, &step},
769	                Tensor{MEMORY_GPU, TYPE_INT32, {local_batch_size * beam_width}, sequence_lengths + id_offset},
770	                Tensor{MEMORY_GPU,
771	                       data_type,
772	                       {1, head_num_, max_seq_len + 1, max_seq_len + 1},
773	                       decoding_weights->position_embedding_type == PositionEmbeddingType::relative ?
774	                           relative_attention_bias_ :
775	                           nullptr},
776	                Tensor{MEMORY_CPU, TYPE_UINT32, {1}, &ite},
777	                Tensor{MEMORY_GPU,
778	                       TYPE_INT32,
779	                       {local_batch_size, beam_width, max_seq_len + 1},
780	                       beam_width > 1 ? cache_indirections_[src_indir_idx] + id_offset * (max_seq_len + 1) : nullptr}};
781	            if (has_ia3_tasks) {
782	                decoder_input_tensors.push_back(input_tensors->at("ia3_tasks").slice({local_batch_size}, id_offset));
783	            }
784	
785	            std::vector<Tensor> decoder_output_tensors{
786	                Tensor{MEMORY_GPU,
787	                       data_type,
788	                       {local_batch_size * beam_width, d_model_},
789	                       decoder_output_buf_ + d_model_offset},
790	                Tensor{MEMORY_GPU, data_type, self_k_cache_shape, key_cache_},
791	                Tensor{MEMORY_GPU, data_type, self_v_cache_shape, value_cache_},
792	                Tensor{MEMORY_GPU, data_type, mem_cache_shape, key_mem_cache_},
793	                Tensor{MEMORY_GPU, data_type, mem_cache_shape, value_mem_cache_}};
794	
795	            if (output_tensors->isExist("cross_attentions")) {
796	                decoder_output_tensors.push_back(Tensor{
797	                    MEMORY_GPU,
798	                    TYPE_FP32,
799	                    output_tensors->at("cross_attentions").shape,
800	                    output_tensors->at("cross_attentions").data,
801	                    {(size_t)id_offset,
802	                     batch_size * beam_width * head_num_ / tensor_para_.world_size_ * max_seq_len * mem_max_seq_len}});
803	            }
804	
805	            decoder_->forward(
806	                &decoder_output_tensors, &decoder_input_tensors, &decoding_weights->decoder_layer_weights);
807	
808	            bool t5_with_bias = decoding_weights->t5_with_bias;
809	
810	            const cudaDataType_t gemm_data_type = getCudaDataType<T>();
811	
812	            if (pipeline_para_.rank_ == pipeline_para_.world_size_ - 1) {
813	                invokeGeneralT5LayerNorm(normed_decoder_output_buf_ + d_model_offset,
814	                                         decoder_output_buf_ + d_model_offset,
815	                                         decoding_weights->post_decoder_layernorm.gamma,
816	                                         decoding_weights->post_decoder_layernorm.beta,
817	                                         layernorm_eps_,
818	                                         local_batch_size * beam_width,
819	                                         d_model_,
820	                                         stream_);
821	                sync_check_cuda_error();
822	
823	                DataType logits_data_type = data_type;
824	
825	                // bf16 logits computation fallback to fp32
826	                if (tensor_para_.world_size_ == 1) {
827	                    float alpha = (!t5_with_bias && tie_word_embeddings_) ? 1.0f / sqrt(d_model_) : 1.0f;
828	                    float beta  = 0.0f;
829	#ifdef ENABLE_BF16
830	                    if (std::is_same<T, __nv_bfloat16>::value) {
831	                        logits_data_type = TYPE_FP32;
832	#else
833	                    if (false) {
834	#endif
835	                        cublas_wrapper_->Gemm(CUBLAS_OP_T,
836	                                              CUBLAS_OP_N,
837	                                              vocab_size_padded_,  // n
838	                                              local_batch_size * beam_width,
839	                                              d_model_,  // k
840	                                              &alpha,
841	                                              padded_embedding_kernel_ptr_,
842	                                              gemm_data_type,
843	                                              d_model_,  // k
844	                                              normed_decoder_output_buf_ + d_model_offset,
845	                                              gemm_data_type,
846	                                              d_model_,  // k
847	                                              &beta,
848	                                              logits_buf_ + vocab_size_units_offset,
849	                                              CUDA_R_32F,
850	                                              vocab_size_padded_, /* n */
851	                                              CUDA_R_32F,
852	                                              cublasGemmAlgo_t(-1));
853	                    }
854	                    else {
855	                        cublas_wrapper_->Gemm(CUBLAS_OP_T,
856	                                              CUBLAS_OP_N,
857	                                              vocab_size_padded_,  // n
858	                                              local_batch_size * beam_width,
859	                                              d_model_,  // k
860	                                              padded_embedding_kernel_ptr_,
861	                                              d_model_,  // k
862	                                              normed_decoder_output_buf_ + d_model_offset,
863	                                              d_model_,  // k
864	                                              logits_buf_ + vocab_size_units_offset,
865	                                              vocab_size_padded_ /* n */,
866	                                              alpha,
867	                                              beta);
868	                    }
869	                }
870	                else {
871	                    const int local_vocab_size = vocab_size_padded_ / tensor_para_.world_size_;
872	                    float     alpha            = (!t5_with_bias && tie_word_embeddings_) ? 1.0f / sqrt(d_model_) : 1.0f;
873	                    float     beta             = 0.0f;
874	#ifdef ENABLE_BF16
875	                    if (std::is_same<T, __nv_bfloat16>::value) {
876	                        logits_data_type = TYPE_FP32;
877	#else
878	                    if (false) {
879	#endif
880	                        cublas_wrapper_->Gemm(
881	                            CUBLAS_OP_T,
882	                            CUBLAS_OP_N,
883	                            local_vocab_size,  // n
884	                            local_batch_size * beam_width,
885	                            d_model_,  // k
886	                            &alpha,
887	                            padded_embedding_kernel_ptr_ + tensor_para_.rank_ * local_vocab_size * d_model_,
888	                            gemm_data_type,
889	                            d_model_,  // k
890	                            normed_decoder_output_buf_ + d_model_offset,
891	                            gemm_data_type,
892	                            d_model_,  // k
893	                            &beta,
894	                            nccl_logits_buf_ + vocab_size_units_offset
895	                                + tensor_para_.rank_ * local_batch_size * beam_width * local_vocab_size,
896	                            CUDA_R_32F,
897	                            local_vocab_size, /* n */
898	                            CUDA_R_32F,
899	                            cublasGemmAlgo_t(-1));
900	                    }
901	                    else {
902	                        cublas_wrapper_->Gemm(
903	                            CUBLAS_OP_T,
904	                            CUBLAS_OP_N,
905	                            local_vocab_size,  // n
906	                            local_batch_size * beam_width,
907	                            d_model_,  // k
908	                            padded_embedding_kernel_ptr_ + tensor_para_.rank_ * local_vocab_size * d_model_,
909	                            d_model_,  // k
910	                            normed_decoder_output_buf_ + d_model_offset,
911	                            d_model_,  // k
912	                            nccl_logits_buf_ + vocab_size_units_offset
913	                                + tensor_para_.rank_ * local_batch_size * beam_width * local_vocab_size,
914	                            local_vocab_size /* n */,
915	                            alpha,
916	                            beta);
917	                    }
918	                    ftNcclAllGather(nccl_logits_buf_ + vocab_size_units_offset,
919	                                    nccl_logits_buf_ + vocab_size_units_offset,
920	                                    local_batch_size * beam_width * local_vocab_size,
921	                                    tensor_para_.rank_,
922	                                    tensor_para_,
923	                                    stream_);
924	                    invokeTransposeAxis01(logits_buf_ + vocab_size_units_offset,
925	                                          nccl_logits_buf_ + vocab_size_units_offset,
926	                                          tensor_para_.world_size_,
927	                                          local_batch_size * beam_width,
928	                                          local_vocab_size,
929	                                          stream_);
930	                }
931	
932	                if (t5_with_bias) {
933	                    invokeGenericActivation<IdentityActivation, DynamicDecodeType, T>(
934	                        logits_buf_ + vocab_size_units_offset,
935	                        padded_post_decoder_embedding_bias_ptr_,
936	                        nullptr,
937	                        nullptr,
938	                        nullptr,
939	                        nullptr,
940	                        local_batch_size * beam_width,
941	                        vocab_size_padded_,
942	                        0,
943	                        nullptr,
944	                        nullptr,
945	                        stream_);
946	                }
947	
948	                int       tmp_local_batch_size       = local_batch_size;
949	                bool      is_initialize_random_table = step == 1;
950	                TensorMap dynamic_decode_input_tensors(
951	                    {{"logits",
952	                      Tensor{MEMORY_GPU, logits_data_type, {batch_size, beam_width, vocab_size_padded_}, logits_buf_}},
953	                     {"step", Tensor{MEMORY_CPU, TYPE_INT32, {1}, &step}},
954	                     {"max_input_length", Tensor{MEMORY_CPU, TYPE_INT32, {1}, &max_input_length}},
955	                     {"ite", Tensor{MEMORY_CPU, TYPE_UINT32, {1}, &ite}},
956	                     {"end_id", Tensor{MEMORY_GPU, TYPE_INT32, {batch_size}, end_ids_buf_}},
957	                     {"local_batch_size", Tensor{MEMORY_CPU, TYPE_INT32, {1}, &tmp_local_batch_size}},
958	                     {"is_initialize_random_table", Tensor{MEMORY_CPU, TYPE_BOOL, {1}, &is_initialize_random_table}}});
959	
960	                if (cache_indirections_[src_indir_idx] != nullptr) {
961	                    dynamic_decode_input_tensors.insert(
962	                        "src_cache_indirection",
963	                        Tensor{MEMORY_GPU,
964	                               TYPE_INT32,
965	                               {local_batch_size, beam_width, (max_seq_len + 1)},
966	                               cache_indirections_[src_indir_idx] + id_offset * (max_seq_len + 1)});
967	                }
968	
969	                for (auto t = input_tensors->begin(); t != input_tensors->end(); ++t) {
970	                    if (!dynamic_decode_input_tensors.isExist(t->first)) {
971	                        dynamic_decode_input_tensors.insert(*t);
972	                    }
973	                }
974	
975	                // common outputs
976	                TensorMap dynamic_decode_output_tensors(
977	                    {{"output_ids",
978	                      Tensor{MEMORY_GPU, TYPE_INT32, {(max_seq_len + 1), batch_size, beam_width}, output_ids_buf_}},
979	                     {"finished", Tensor{MEMORY_GPU, TYPE_BOOL, {batch_size * beam_width}, finished_buf_}},
980	                     {"parent_ids",
981	                      Tensor{MEMORY_GPU, TYPE_INT32, {(max_seq_len + 1), batch_size, beam_width}, parent_ids_buf_}},
982	                     {"sequence_length", Tensor{MEMORY_GPU, TYPE_INT32, {batch_size * beam_width}, sequence_lengths}}});
983	
984	                if (using_beam_hyps) {
985	                    dynamic_decode_output_tensors.insert("beam_hyps", Tensor{MEMORY_GPU, TYPE_VOID, {1}, &beam_hyps_});
986	                }
987	
988	                // cum_log_probs is necessary for beam search, while it is optional for sampling.
989	                if (beam_width > 1 || output_tensors->isExist("cum_log_probs")) {
990	                    dynamic_decode_output_tensors.insert(
991	                        "cum_log_probs", Tensor{MEMORY_GPU, TYPE_FP32, {batch_size * beam_width}, cum_log_probs_});
992	                }
993	
994	                if (output_tensors->getPtr<float>("output_log_probs", nullptr) != nullptr) {
995	                    dynamic_decode_output_tensors.insert(
996	                        "output_log_probs",
997	                        Tensor{
998	                            MEMORY_GPU, TYPE_FP32, {(max_seq_len + 1), batch_size, beam_width}, output_log_probs_buf_});
999	                }
1000	
1001	                if (cache_indirections_[tgt_indir_idx] != nullptr) {
1002	                    dynamic_decode_output_tensors.insert(
1003	                        "tgt_cache_indirection",
1004	                        Tensor{MEMORY_GPU,
1005	                               TYPE_INT32,
1006	                               {local_batch_size, beam_width, (max_seq_len + 1)},
1007	                               cache_indirections_[tgt_indir_idx] + id_offset * (max_seq_len + 1)});
1008	                }
1009	
1010	                for (auto t = output_tensors->begin(); t != output_tensors->end(); ++t) {
1011	                    // Handle exceptions.
1012	                    if (t->first == "cum_log_probs" || t->first == "output_log_probs") {
1013	                        continue;
1014	                    }
1015	                    dynamic_decode_output_tensors.insert(*t);
1016	                }
1017	
1018	                dynamic_decode_layer_->forward(&dynamic_decode_output_tensors, &dynamic_decode_input_tensors);
1019	            }
1020	        }
1021	
1022	        if (pipeline_para_.world_size_ > 1) {
1023	            ftNcclGroupStart();
1024	            ftNcclBroadCast(output_ids_buf_ + step * batch_size * beam_width,
1025	                            batch_size * beam_width,
1026	                            pipeline_para_.world_size_ - 1,
1027	                            pipeline_para_,
1028	                            stream_);
1029	
1030	            ftNcclBroadCast(
1031	                sequence_lengths, batch_size * beam_width, pipeline_para_.world_size_ - 1, pipeline_para_, stream_);
1032	
1033	            ftNcclBroadCast(
1034	                finished_buf_, batch_size * beam_width, pipeline_para_.world_size_ - 1, pipeline_para_, stream_);
1035	
1036	            if (beam_width > 1) {
1037	                ftNcclBroadCast(cache_indirections_[tgt_indir_idx],
1038	                                batch_size * beam_width * (max_seq_len + 1),
1039	                                pipeline_para_.world_size_ - 1,
1040	                                pipeline_para_,
1041	                                stream_);
1042	            }
1043	            ftNcclGroupEnd();
1044	            // throw errors when detected
1045	            ftNcclStreamSynchronize(tensor_para_, pipeline_para_, stream_);
1046	            sync_check_cuda_error();
1047	        }
1048	
1049	        cudaD2Hcpy(h_finished_buf_, finished_buf_, batch_size * beam_width);
1050	        uint sum = 0;
1051	        for (uint i = 0; i < batch_size * beam_width; i++) {
1052	            sum += (int)h_finished_buf_[i];
1053	        }
1054	        if (sum == batch_size * beam_width) {
1055	            break;
1056	        }
1057	        else if (step < (int)max_seq_len && token_generated_cb_) {
1058	            setOutputTensors(output_tensors, input_tensors);
1059	            sendTensorsToFirstPipelineNode(output_tensors, input_tensors);
1060	            if (pipeline_para_.rank_ == 0 && tensor_para_.rank_ == 0) {
1061	                token_generated_cb_(output_tensors, token_generated_ctx_);
1062	            }
1063	        }
1064	    }
1065	
1066	    setOutputTensors(output_tensors, input_tensors);
1067	    sendTensorsToFirstPipelineNode(output_tensors, input_tensors);
1068	
1069	    if (is_free_buffer_after_forward_) {
1070	        freeBuffer();
1071	    }
1072	}
1073	
1074	template class T5Decoding<float>;
1075	template class T5Decoding<half>;
1076	#ifdef ENABLE_BF16
1077	template class T5Decoding<__nv_bfloat16>;
1078	#endif
1079	
1080	}  // namespace fastertransformer
