23	template<typename T>
24	void GptJDecoder<T>::initialize()
25	{
26	    self_attention_layer_ = new TensorParallelDecoderSelfAttentionLayer<T>(max_batch_size_,
27	                                                                           head_num_,
28	                                                                           size_per_head_,
29	                                                                           rotary_embedding_dim_,
30	                                                                           neox_rotary_style_,
31	                                                                           tensor_para_,
32	                                                                           stream_,
33	                                                                           cublas_wrapper_,
34	                                                                           allocator_,
35	                                                                           true,
36	                                                                           is_free_buffer_after_forward_,
37	                                                                           false,
38	                                                                           0,
39	                                                                           custom_all_reduce_comm_,
40	                                                                           enable_custom_all_reduce_);
41	
42	    ffn_layer_ = new TensorParallelGeluFfnLayer<T>(max_batch_size_,
43	                                                   1,
44	                                                   head_num_,
45	                                                   size_per_head_,
46	                                                   0,  // expert_num
47	                                                   inter_size_,
48	                                                   tensor_para_,
49	                                                   stream_,
50	                                                   cublas_wrapper_,
51	                                                   allocator_,
52	                                                   true,
53	                                                   is_free_buffer_after_forward_,
54	                                                   false,
55	                                                   0,
56	                                                   false,  // use_gated_activation = false;
57	                                                   custom_all_reduce_comm_,
58	                                                   enable_custom_all_reduce_);
59	}
60	
61	template<typename T>
62	void GptJDecoder<T>::allocateBuffer()
63	{
64	    FT_CHECK(false);
65	}
66	
67	template<typename T>
68	void GptJDecoder<T>::allocateBuffer(size_t batch_size)
69	{
70	    decoder_normed_input_ = reinterpret_cast<T*>(
71	        allocator_->reMalloc(decoder_normed_input_, sizeof(T) * batch_size * hidden_units_, false));
72	    self_attn_output_ =
73	        reinterpret_cast<T*>(allocator_->reMalloc(self_attn_output_, sizeof(T) * batch_size * hidden_units_, false));
74	    ffn_output_ =
75	        reinterpret_cast<T*>(allocator_->reMalloc(ffn_output_, sizeof(T) * batch_size * hidden_units_, false));
76	    decoder_layer_output_ = reinterpret_cast<T*>(
77	        allocator_->reMalloc(decoder_layer_output_, sizeof(T) * batch_size * hidden_units_, false));
78	    is_allocate_buffer_ = true;
79	}
80	
81	template<typename T>
82	void GptJDecoder<T>::freeBuffer()
83	{
84	    if (is_allocate_buffer_ == true) {
85	        allocator_->free((void**)(&decoder_normed_input_));
86	        allocator_->free((void**)(&self_attn_output_));
87	        allocator_->free((void**)(&ffn_output_));
88	        allocator_->free((void**)(&decoder_layer_output_));
89	        is_allocate_buffer_ = false;
90	    }
91	}
