93	template<typename T>
94	bool GptJDecoder<T>::isValidLayerParallelId(uint l)
95	{
96	    int local_num_layer = (int)(ceil(num_layer_ * 1.0f / pipeline_para_.world_size_));
97	    return l < num_layer_ && (l >= local_num_layer * pipeline_para_.rank_)
98	           && (l < local_num_layer * (pipeline_para_.rank_ + 1));
99	}
100	
101	template<typename T>
102	bool GptJDecoder<T>::isFirstLayerParallelId(uint l)
103	{
104	    int local_num_layer = (int)(ceil(num_layer_ * 1.0f / pipeline_para_.world_size_));
105	    return l < num_layer_ && (l == local_num_layer * pipeline_para_.rank_);
106	}
107	
108	template<typename T>
109	bool GptJDecoder<T>::isLastLayerParallelId(uint l)
110	{
111	    int local_num_layer = (int)(ceil(num_layer_ * 1.0f / pipeline_para_.world_size_));
112	    return l < num_layer_ && (l == local_num_layer * (pipeline_para_.rank_ + 1) - 1);
113	}
114	
115	template<typename T>
116	int GptJDecoder<T>::getFirstLayerParallelId()
117	{
118	    int local_num_layer = (int)(ceil(num_layer_ * 1.0f / pipeline_para_.world_size_));
119	    return local_num_layer * pipeline_para_.rank_;
120	}
