122	template<typename T>
123	GptJDecoder<T>::GptJDecoder(size_t                              max_batch_size,
124	                            size_t                              head_num,
125	                            size_t                              size_per_head,
126	                            size_t                              inter_size,
127	                            size_t                              num_layer,
128	                            size_t                              rotary_embedding_dim,
129	                            bool                                neox_rotary_style,
130	                            float                               layernorm_eps,
131	                            NcclParam                           tensor_para,
132	                            NcclParam                           pipeline_para,
133	                            cudaStream_t                        stream,
134	                            cublasMMWrapper*                    cublas_wrapper,
135	                            IAllocator*                         allocator,
136	                            bool                                is_free_buffer_after_forward,
137	                            std::shared_ptr<AbstractCustomComm> custom_all_reduce_comm,
138	                            int                                 enable_custom_all_reduce):
139	    BaseLayer(stream, cublas_wrapper, allocator, is_free_buffer_after_forward),
140	    max_batch_size_(max_batch_size),
141	    head_num_(head_num),
142	    size_per_head_(size_per_head),
143	    inter_size_(inter_size),
144	    num_layer_(num_layer),
145	    rotary_embedding_dim_(rotary_embedding_dim),
146	    neox_rotary_style_(neox_rotary_style),
147	    layernorm_eps_(layernorm_eps),
148	    hidden_units_(head_num_ * size_per_head),
149	    tensor_para_(tensor_para),
150	    pipeline_para_(pipeline_para),
151	    custom_all_reduce_comm_(custom_all_reduce_comm),
152	    enable_custom_all_reduce_(enable_custom_all_reduce)
153	{
154	    initialize();
155	}
156	
157	template<typename T>
158	GptJDecoder<T>::GptJDecoder(GptJDecoder<T> const& decoder):
159	    BaseLayer(decoder.stream_, decoder.cublas_wrapper_, decoder.allocator_, decoder.is_free_buffer_after_forward_),
160	    max_batch_size_(decoder.max_batch_size_),
161	    head_num_(decoder.head_num_),
162	    size_per_head_(decoder.size_per_head_),
163	    inter_size_(decoder.inter_size_),
164	    num_layer_(decoder.num_layer_),
165	    rotary_embedding_dim_(decoder.rotary_embedding_dim_),
166	    layernorm_eps_(decoder.layernorm_eps_),
167	    hidden_units_(decoder.hidden_units_),
168	    tensor_para_(decoder.tensor_para_),
169	    pipeline_para_(decoder.pipeline_para_),
170	    custom_all_reduce_comm_(decoder.custom_all_reduce_comm_),
171	    enable_custom_all_reduce_(decoder.enable_custom_all_reduce_)
172	{
173	    initialize();
174	}
175	
176	template<typename T>
177	GptJDecoder<T>::~GptJDecoder()
178	{
179	    delete self_attention_layer_;
180	    delete ffn_layer_;
181	    freeBuffer();
182	}
183	
184	template<typename T>
185	void GptJDecoder<T>::forward(std::vector<Tensor>*                          output_tensors,
186	                             const std::vector<Tensor>*                    input_tensors,
187	                             const std::vector<GptJDecoderLayerWeight<T>>* gpt_decoder_layer_weight)
188	{
189	    FT_CHECK(false);
190	}
191	
192	template<typename T>
193	void GptJDecoder<T>::forward(std::unordered_map<std::string, Tensor>*       output_tensors,
194	                             const std::unordered_map<std::string, Tensor>* input_tensors,
195	                             const std::vector<GptJDecoderLayerWeight<T>>*  gpt_decoder_layer_weight)
196	{
197	    // input tensors:
198	    //      decoder_input [local_batch_size, hidden_dimension],
199	    //      finished [local_batch_size],
200	    //      sequence_lengths [local_batch_size]
201	    //      total_padding_tokens [local_batch_size],
202	    //      d_prefix_prompt_lengths [local_batch_size],on GPU
203	    //      max_prefix_prompt_length [1] on cpu
204	    //      max_input_length [1] on cpu
205	    //      step [1] on cpu
206	    //      ite [1] on cpu
207	    //      cache_indirection [local_batch_size / beam_width, beam_width, memory_len]
208	    //              Here, local_batch_size contains the beam_width, so local_batch_size / beam_width
209	    //              is real local_batch_size.
210	    //      masked_tokens[local_batch_size, memory_len]
211	
212	    // output tensors:
213	    //      decoder_output [local_batch_size, hidden_dimension],
214	    //      key_cache [num_layer, batch_size, head_num, size_per_head // x, memory_len, x]
215	    //      value_cache [num_layer, batch_size, head_num, memory_len, size_per_head]
216	
217	    FT_CHECK(input_tensors->size() == 11);
218	    FT_CHECK(output_tensors->size() == 3);
219	
220	    const DataType data_type        = getTensorType<T>();
221	    const size_t   local_batch_size = input_tensors->at("decoder_input").shape[0];
222	    const int      ite              = input_tensors->at("ite").getVal<const int>();
223	    allocateBuffer(local_batch_size);
224	
225	    T* decoder_input  = input_tensors->at("decoder_input").getPtr<T>();
226	    T* decoder_output = output_tensors->at("decoder_output").getPtr<T>();
227	
228	    Tensor&             k_cache = output_tensors->at("key_cache");
229	    Tensor&             v_cache = output_tensors->at("value_cache");
230	    std::vector<size_t> self_k_cache_size;
231	    self_k_cache_size.push_back(local_batch_size);
232	    for (auto t = k_cache.shape.begin() + 2; t != k_cache.shape.end(); ++t) {
233	        self_k_cache_size.push_back(*t);
234	    }
235	    std::vector<size_t> self_v_cache_size;
236	    self_v_cache_size.push_back(local_batch_size);
237	    for (auto t = v_cache.shape.begin() + 2; t != v_cache.shape.end(); ++t) {
238	        self_v_cache_size.push_back(*t);
239	    }
240	
241	    for (uint l = 0; l < num_layer_; l++) {
242	        if (isValidLayerParallelId(l) == false) {
243	            continue;
244	        }
245	        T* layer_input  = (l == 0) ? decoder_input : decoder_layer_output_;
246	        T* layer_output = (l == num_layer_ - 1) ? decoder_output : decoder_layer_output_;
247	
248	        if (isFirstLayerParallelId(l) == true && pipeline_para_.rank_ != 0 && pipeline_para_.world_size_ > 1) {
249	            int data_size = local_batch_size * hidden_units_ / tensor_para_.world_size_;
250	            // ftNcclRecv(layer_input, local_batch_size * hidden_units_, pipeline_para_.rank_ - 1, pipeline_para_,
251	            // stream_);
252	
253	            ftNcclRecv(layer_input + data_size * tensor_para_.rank_,
254	                       data_size,
255	                       pipeline_para_.rank_ - 1,
256	                       pipeline_para_,
257	                       stream_);
258	            if (tensor_para_.world_size_ > 1) {
259	                ftNcclAllGather(layer_input, layer_input, data_size, tensor_para_.rank_, tensor_para_, stream_);
260	            }
261	        }
262	
263	        invokeGeneralLayerNorm(decoder_normed_input_,
264	                               layer_input,
265	                               gpt_decoder_layer_weight->at(l).pre_layernorm_weights.gamma,
266	                               gpt_decoder_layer_weight->at(l).pre_layernorm_weights.beta,
267	                               layernorm_eps_,
268	                               local_batch_size,
269	                               hidden_units_,
270	                               (float*)nullptr,
271	                               0,
272	                               stream_);
273	        sync_check_cuda_error();
274	
275	        TensorMap self_attention_input_tensors(*input_tensors);
276	        self_attention_input_tensors.insert(
277	            "input_query", Tensor{MEMORY_GPU, data_type, {local_batch_size, hidden_units_}, decoder_normed_input_});
278	
279	        size_t cache_offset = l - getFirstLayerParallelId();
280	        for (auto t = k_cache.shape.begin() + 1; t != k_cache.shape.end(); ++t) {
281	            cache_offset *= *t;
282	        };
283	        size_t ite_cache_offset = ite * local_batch_size;
284	        for (auto t = k_cache.shape.begin() + 2; t != k_cache.shape.end(); ++t) {
285	            ite_cache_offset *= *t;
286	        }
287	        cache_offset += ite_cache_offset;
288	
289	        TensorMap self_attention_output_tensors{
290	            {"hidden_features", Tensor{MEMORY_GPU, data_type, {local_batch_size, hidden_units_}, self_attn_output_}},
291	            {"key_cache", Tensor{MEMORY_GPU, data_type, self_k_cache_size, k_cache.getPtrWithOffset(cache_offset)}},
292	            {"value_cache", Tensor{MEMORY_GPU, data_type, self_v_cache_size, v_cache.getPtrWithOffset(cache_offset)}}};
293	
294	        self_attention_layer_->forward(&self_attention_output_tensors,
295	                                       &self_attention_input_tensors,
296	                                       &gpt_decoder_layer_weight->at(l).self_attention_weights);
297	
298	        TensorMap ffn_input_tensors(
299	            {{"ffn_input", Tensor{MEMORY_GPU, data_type, {local_batch_size, hidden_units_}, decoder_normed_input_}}});
300	        TensorMap ffn_output_tensors(
301	            {{"ffn_output", Tensor{MEMORY_GPU, data_type, {local_batch_size, hidden_units_}, ffn_output_}}});
302	        ffn_layer_->forward(&ffn_output_tensors, &ffn_input_tensors, &gpt_decoder_layer_weight->at(l).ffn_weights);
303	
304	        invokeAddBiasAttentionFfnResidual(layer_output,
305	                                          ffn_output_,
306	                                          self_attn_output_,
307	                                          layer_input,
308	                                          gpt_decoder_layer_weight->at(l).ffn_weights.output_weight.bias,
309	                                          local_batch_size,
310	                                          hidden_units_,
311	                                          stream_);
312	        sync_check_cuda_error();
313	
314	        if (isLastLayerParallelId(l) == true && pipeline_para_.rank_ != pipeline_para_.world_size_ - 1
315	            && pipeline_para_.world_size_ > 1) {
316	            int data_size = local_batch_size * hidden_units_ / tensor_para_.world_size_;
317	            // ftNcclSend(layer_output, local_batch_size * hidden_units_, pipeline_para_.rank_ + 1, pipeline_para_,
318	            // stream_);
319	
320	            ftNcclSend(layer_output + data_size * tensor_para_.rank_,
321	                       data_size,
322	                       pipeline_para_.rank_ + 1,
323	                       pipeline_para_,
324	                       stream_);
325	        }
326	    }
327	
328	    if (is_free_buffer_after_forward_ == true) {
329	        freeBuffer();
330	    }
331	}
332	
333	template class GptJDecoder<float>;
334	template class GptJDecoder<half>;
335	#ifdef ENABLE_BF16
336	template class GptJDecoder<__nv_bfloat16>;
337	#endif
338	
339	}  // namespace fastertransformer
