185	template<typename T>
186	void GptNeoXDecoder<T>::forward(std::vector<Tensor>*                              output_tensors,
187	                                const std::vector<Tensor>*                        input_tensors,
188	                                const std::vector<GptNeoXDecoderLayerWeight<T>*>* gpt_decoder_layer_weight)
189	{
190	    FT_CHECK(false);
