192	
193	template<typename T>
194	void GptNeoXDecoder<T>::forward(std::unordered_map<std::string, Tensor>*          output_tensors,
195	                                const std::unordered_map<std::string, Tensor>*    input_tensors,
196	                                const std::vector<GptNeoXDecoderLayerWeight<T>*>* gpt_decoder_layer_weight)
197	{
198	    // input tensors:
199	    //      decoder_input [local_batch_size, hidden_dimension],
200	    //      finished [local_batch_size],
201	    //      sequence_lengths [local_batch_size]
202	    //      total_padding_tokens [local_batch_size],
203	    //      max_input_length [1] on cpu
204	    //      d_prefix_prompt_lengths [local_batch_size], on GPU
205	    //      max_prefix_prompt_length [1] on cpu
206	    //      step [1] on cpu
207	    //      ite [1] on cpu
208	    //      cache_indirection [local_batch_size / beam_width, beam_width, memory_len]
209	    //              Here, local_batch_size contains the beam_width, so local_batch_size / beam_width
210	    //              is real local_batch_size.
211	    //      masked_tokens[local_batch_size, memory_len]
212	
213	    // output tensors:
214	    //      decoder_output [local_batch_size, hidden_dimension],
215	    //      key_cache [num_layer, batch_size, head_num, size_per_head // x, memory_len, x]
216	    //      value_cache [num_layer, batch_size, head_num, memory_len, size_per_head]
217	
218	    FT_CHECK(input_tensors->size() == 11);
219	    FT_CHECK(output_tensors->size() == 3);
220	
221	    const DataType data_type        = getTensorType<T>();
222	    const size_t   local_batch_size = input_tensors->at("decoder_input").shape[0];
223	    allocateBuffer(local_batch_size);
224	    const int ite = input_tensors->at("ite").getVal<const int>();
225	
226	    T* decoder_input  = input_tensors->at("decoder_input").getPtr<T>();
227	    T* decoder_output = output_tensors->at("decoder_output").getPtr<T>();
228	
229	    Tensor&             k_cache = output_tensors->at("key_cache");
230	    Tensor&             v_cache = output_tensors->at("value_cache");
231	    std::vector<size_t> self_k_cache_size;
232	    self_k_cache_size.push_back(local_batch_size);
233	    for (auto t = k_cache.shape.begin() + 2; t != k_cache.shape.end(); ++t) {
234	        self_k_cache_size.push_back(*t);
235	    }
236	    std::vector<size_t> self_v_cache_size;
237	    self_v_cache_size.push_back(local_batch_size);
238	    for (auto t = v_cache.shape.begin() + 2; t != v_cache.shape.end(); ++t) {
239	        self_v_cache_size.push_back(*t);
240	    }
241	
242	    for (uint l = 0; l < num_layer_; l++) {
243	        if (isValidLayerParallelId(l) == false) {
244	            continue;
245	        }
246	        T* layer_input  = (l == 0) ? decoder_input : decoder_layer_output_;
247	        T* layer_output = (l == num_layer_ - 1) ? decoder_output : decoder_layer_output_;
248	
249	        if (isFirstLayerParallelId(l) == true && pipeline_para_.rank_ != 0 && pipeline_para_.world_size_ > 1) {
250	            int data_size = local_batch_size * hidden_units_ / tensor_para_.world_size_;
251	            // ftNcclRecv(layer_input, local_batch_size * hidden_units_, pipeline_para_.rank_ - 1, pipeline_para_,
252	            // stream_);
253	
254	            ftNcclRecv(layer_input + data_size * tensor_para_.rank_,
255	                       data_size,
256	                       pipeline_para_.rank_ - 1,
257	                       pipeline_para_,
258	                       stream_);
259	            if (tensor_para_.world_size_ > 1) {
260	                ftNcclAllGather(layer_input, layer_input, data_size, tensor_para_.rank_, tensor_para_, stream_);
261	            }
262	        }
263	
264	        invokeGeneralLayerNorm(decoder_normed_input_,
265	                               layer_input,
266	                               gpt_decoder_layer_weight->at(l)->pre_layernorm_weights.gamma,
267	                               gpt_decoder_layer_weight->at(l)->pre_layernorm_weights.beta,
268	                               layernorm_eps_,
269	                               local_batch_size,
270	                               hidden_units_,
271	                               (float*)nullptr,
272	                               0,
273	                               stream_);
274	        sync_check_cuda_error();
275	
276	        TensorMap self_attention_input_tensors(*input_tensors);
277	        self_attention_input_tensors.insert(
278	            "input_query", Tensor{MEMORY_GPU, data_type, {local_batch_size, hidden_units_}, decoder_normed_input_});
279	
280	        size_t cache_offset = l - getFirstLayerParallelId();
281	        for (auto t = k_cache.shape.begin() + 1; t != k_cache.shape.end(); ++t) {
282	            cache_offset *= *t;
283	        };
284	        size_t ite_cache_offset = ite * local_batch_size;
285	        for (auto t = k_cache.shape.begin() + 2; t != k_cache.shape.end(); ++t) {
286	            ite_cache_offset *= *t;
287	        }
288	        cache_offset += ite_cache_offset;
289	
290	        TensorMap self_attention_output_tensors{
291	            {"hidden_features", Tensor{MEMORY_GPU, data_type, {local_batch_size, hidden_units_}, self_attn_output_}},
292	            {"key_cache", Tensor{MEMORY_GPU, data_type, self_k_cache_size, k_cache.getPtrWithOffset(cache_offset)}},
293	            {"value_cache", Tensor{MEMORY_GPU, data_type, self_v_cache_size, v_cache.getPtrWithOffset(cache_offset)}}};
294	
295	        self_attention_layer_->forward(&self_attention_output_tensors,
296	                                       &self_attention_input_tensors,
297	                                       &gpt_decoder_layer_weight->at(l)->self_attention_weights);
298	        if (use_gptj_residual_) {
299	            invokeGeneralLayerNorm(decoder_normed_input_,
300	                                   layer_input,
301	                                   gpt_decoder_layer_weight->at(l)->post_attention_layernorm_weights.gamma,
302	                                   gpt_decoder_layer_weight->at(l)->post_attention_layernorm_weights.beta,
303	                                   layernorm_eps_,
304	                                   local_batch_size,
305	                                   hidden_units_,
306	                                   (float*)nullptr,
307	                                   0,
308	                                   stream_);
309	        }
310	        else {
311	            invokeGeneralAddBiasResidualPreLayerNorm(
312	                self_attn_output_,
313	                decoder_normed_input_,
314	                self_attn_output_,
315	                layer_input,
316	                gpt_decoder_layer_weight->at(l)->post_attention_layernorm_weights.gamma,
317	                gpt_decoder_layer_weight->at(l)->post_attention_layernorm_weights.beta,
318	                gpt_decoder_layer_weight->at(l)->self_attention_weights.attention_output_weight.bias,
319	                layernorm_eps_,
320	                local_batch_size,
321	                hidden_units_,
322	                (float*)nullptr,
323	                (float*)nullptr,
324	                (float*)nullptr,
325	                (float*)nullptr,
326	                0,
327	                stream_);
328	        }
329	
330	        TensorMap ffn_input_tensors(
331	            {{"ffn_input", Tensor{MEMORY_GPU, data_type, {local_batch_size, hidden_units_}, decoder_normed_input_}}});
332	        TensorMap ffn_output_tensors({{"ffn_output",
333	                                       Tensor{MEMORY_GPU,
334	                                              data_type,
335	                                              {local_batch_size, hidden_units_},
336	                                              use_gptj_residual_ ? ffn_output_ : layer_output}}});
337	        ffn_layer_->forward(&ffn_output_tensors, &ffn_input_tensors, &gpt_decoder_layer_weight->at(l)->ffn_weights);
338	
339	        if (use_gptj_residual_) {
340	            // Original workflow:
341	            //      layer_output = layer_input + reduceSum(ffn_output + self_attn_output + ffn_output_bias)
342	            // Our workflow:
343	            //      layer_output = reduceSum(ffn_output + self_attn_output + ffn_output_bias + layer_input / TP_size)
344	            // They are equivalent on math, but we can use same buffer for layer_input and layer_output
345	            invokeAddBiasAttentionFfnResidual(layer_output,
346	                                              ffn_output_,
347	                                              self_attn_output_,
348	                                              layer_input,
349	                                              gpt_decoder_layer_weight->at(l)->ffn_weights.output_weight.bias,
350	                                              local_batch_size,
351	                                              hidden_units_,
352	                                              tensor_para_.world_size_,
353	                                              stream_);
354	            if (tensor_para_.world_size_ > 1) {
355	                ftNcclAllReduceSum(layer_output, layer_output, local_batch_size * hidden_units_, tensor_para_, stream_);
356	            }
357	        }
358	        else {
359	            invokeAddBiasResidual(layer_output,
360	                                  self_attn_output_,
361	                                  gpt_decoder_layer_weight->at(l)->ffn_weights.output_weight.bias,
362	                                  local_batch_size,
363	                                  hidden_units_,
364	                                  stream_);
365	        }
366	
367	        sync_check_cuda_error();
368	
369	        if (isLastLayerParallelId(l) == true && pipeline_para_.rank_ != pipeline_para_.world_size_ - 1
370	            && pipeline_para_.world_size_ > 1) {
371	            int data_size = local_batch_size * hidden_units_ / tensor_para_.world_size_;
372	            // ftNcclSend(layer_output, local_batch_size * hidden_units_, pipeline_para_.rank_ + 1, pipeline_para_,
373	            // stream_);
374	
375	            ftNcclSend(layer_output + data_size * tensor_para_.rank_,
376	                       data_size,
377	                       pipeline_para_.rank_ + 1,
378	                       pipeline_para_,
379	                       stream_);
380	        }
381	    }
382	
383	    if (is_free_buffer_after_forward_ == true) {
384	        freeBuffer();
385	    }
386	}
387	
388	template class GptNeoXDecoder<float>;
389	template class GptNeoXDecoder<half>;
390	
391	}  // namespace fastertransformer
